  1→/**
  2→ * Sandbox Agent Adapter -- port types and adapter factories.
  3→ *
  4→ * Port types define the contract for interacting with a SandboxAgent server.
  5→ * The adapter abstracts at the SDK level: one factory wraps the real SDK instance,
  6→ * another provides a test-injectable mock with overridable behavior.
  7→ *
  8→ * Real SDK types are re-exported for use by callers without direct SDK dependency.
  9→ */
 10→import type {
 11→  SandboxAgent,
 12→  Session,
 13→  SessionCreateRequest,
 14→  SessionEvent,
 15→  SessionEventListener,
 16→  SessionPermissionRequest,
 17→  PermissionRequestListener,
 18→  PermissionReply,
 19→  PromptRequest,
 20→  PromptResponse,
 21→} from "sandbox-agent";
 22→
 23→// Re-export SDK types used at port boundaries
 24→export type {
 25→  SessionEvent,
 26→  SessionEventListener,
 27→  SessionPermissionRequest,
 28→  PermissionRequestListener,
 29→  PermissionReply,
 30→  PromptResponse,
 31→};
 32→
 33→// ── Port Types ──
 34→
 35→/**
 36→ * Thin wrapper around the SDK's Session, exposing only the methods Brain needs.
 37→ * Keeps the port boundary narrow -- callers never depend on the full Session class.
 38→ */
 39→export type SessionHandle = {
 40→  id: string;
 41→  prompt: (
 42→    messages: PromptRequest["prompt"],
 43→  ) => Promise<PromptResponse>;
 44→  onEvent: (listener: SessionEventListener) => () => void;
 45→  onPermissionRequest: (listener: PermissionRequestListener) => () => void;
 46→  respondPermission: (permissionId: string, reply: PermissionReply) => Promise<void>;
 47→};
 48→
 49→export type SandboxAgentAdapter = {
 50→  createSession: (request: SessionCreateRequest) => Promise<SessionHandle>;
 51→  resumeSession: (sessionId: string) => Promise<SessionHandle>;
 52→  destroySession: (sessionId: string) => Promise<void>;
 53→};
 54→
 55→// ── Production Adapter Factory ──
 56→
 57→function wrapSession(session: Session): SessionHandle {
 58→  return {
 59→    id: session.id,
 60→    prompt: (messages) => session.prompt(messages),
 61→    onEvent: (listener) => session.onEvent(listener),
 62→    onPermissionRequest: (listener) => session.onPermissionRequest(listener),
 63→    respondPermission: (permissionId, reply) => session.respondPermission(permissionId, reply),
 64→  };
 65→}
 66→
 67→/**
 68→ * Creates a production adapter backed by a real SandboxAgent SDK instance.
 69→ * The SDK instance should be created via `SandboxAgent.start()` or `SandboxAgent.connect()`.
 70→ */
 71→export function createSandboxAgentAdapter(
 72→  sdk: SandboxAgent,
 73→): SandboxAgentAdapter {
 74→  return {
 75→    createSession: async (request) => {
 76→      const session = await sdk.createSession(request);
 77→      return wrapSession(session);
 78→    },
 79→    resumeSession: async (sessionId) => {
 80→      const session = await sdk.resumeSession(sessionId);
 81→      return wrapSession(session);
 82→    },
 83→    destroySession: async (sessionId) => {
 84→      await sdk.destroySession(sessionId);
 85→    },
 86→  };
 87→}
 88→
 89→// ── Mock Adapter Factory ──
 90→
 91→export function createMockAdapter(
 92→  overrides?: Partial<SandboxAgentAdapter>,
 93→): SandboxAgentAdapter {
 94→  const sessions = new Map<string, SessionHandle>();
 95→  const destroyed = new Set<string>();
 96→
 97→  const createHandle = (id: string): SessionHandle => ({
 98→    id,
 99→    prompt: async () => {
100→      if (destroyed.has(id)) {
101→        throw new Error(`Session ${id} has been destroyed`);
102→      }
103→      return { stopReason: "end_turn" as const } as PromptResponse;
104→    },
105→    onEvent: () => () => {},
106→    onPermissionRequest: () => () => {},
107→    respondPermission: async () => {
108→      if (destroyed.has(id)) {
109→        throw new Error(`Session ${id} has been destroyed`);
110→      }
111→    },
112→  });
113→
114→  return {
115→    createSession: async (request) => {
116→      const id = `session-${crypto.randomUUID()}`;
117→      const handle = createHandle(id);
118→      sessions.set(id, handle);
119→      return handle;
120→    },
121→    resumeSession: async (sessionId) => {
122→      if (destroyed.has(sessionId)) {
123→        throw new Error(`Session ${sessionId} has been destroyed`);
124→      }
125→      const existing = sessions.get(sessionId);
126→      if (existing) {
127→        return existing;
128→      }
129→      const handle = createHandle(sessionId);
130→      sessions.set(sessionId, handle);
131→      return handle;
132→    },
133→    destroySession: async (sessionId) => {
134→      sessions.delete(sessionId);
135→      destroyed.add(sessionId);
136→    },
137→    ...overrides,
138→  };
139→}
