  1→/**
  2→ * Orchestrator HTTP route handlers.
  3→ *
  4→ * Pure request->response mappings that delegate to session-lifecycle functions
  5→ * injected via OrchestratorRouteDeps. No direct DB or IO access.
  6→ */
  7→import { jsonError, jsonResponse } from "../http/response";
  8→import { withTracing, type RouteHandler } from "../http/instrumentation";
  9→import { RecordId } from "surrealdb";
 10→import { generateKeyPair } from "../../../shared/dpop";
 11→import { submitIntentForAuthorization } from "../oauth/intent-submission";
 12→import { exchangeIntentForToken } from "../oauth/token-endpoint";
 13→import { evaluatePendingIntent } from "../intent/intent-evaluation";
 14→import {
 15→  computeExpiresAt,
 16→  generateProxyToken,
 17→  hashProxyToken,
 18→  readProxyTokenTtlDays,
 19→} from "../proxy/proxy-token-core";
 20→import type {
 21→  OrchestratorSessionResult,
 22→  SessionStatusResult,
 23→  AbortSessionResult,
 24→  AcceptSessionResult,
 25→  ReviewResult,
 26→  RejectSessionResult,
 27→  PromptSessionResult,
 28→} from "./session-lifecycle";
 29→import { pickDefined } from "./session-lifecycle";
 30→import type { SseRegistry } from "../streaming/sse-registry";
 31→
 32→type BrainAction = {
 33→  type: "brain_action";
 34→  action: string;
 35→  resource: string;
 36→};
 37→
 38→const CLI_AUTHORIZATION_DETAILS: BrainAction[] = [
 39→  { type: "brain_action", action: "read", resource: "workspace" },
 40→  { type: "brain_action", action: "read", resource: "project" },
 41→  { type: "brain_action", action: "read", resource: "task" },
 42→  { type: "brain_action", action: "read", resource: "decision" },
 43→  { type: "brain_action", action: "read", resource: "constraint" },
 44→  { type: "brain_action", action: "read", resource: "change_log" },
 45→  { type: "brain_action", action: "read", resource: "entity" },
 46→  { type: "brain_action", action: "read", resource: "suggestion" },
 47→  { type: "brain_action", action: "read", resource: "intent" },
 48→  { type: "brain_action", action: "reason", resource: "decision" },
 49→  { type: "brain_action", action: "reason", resource: "constraint" },
 50→  { type: "brain_action", action: "reason", resource: "commit" },
 51→  { type: "brain_action", action: "create", resource: "decision" },
 52→  { type: "brain_action", action: "create", resource: "question" },
 53→  { type: "brain_action", action: "create", resource: "task" },
 54→  { type: "brain_action", action: "create", resource: "note" },
 55→  { type: "brain_action", action: "create", resource: "observation" },
 56→  { type: "brain_action", action: "create", resource: "suggestion" },
 57→  { type: "brain_action", action: "create", resource: "session" },
 58→  { type: "brain_action", action: "create", resource: "commit" },
 59→  { type: "brain_action", action: "create", resource: "intent" },
 60→  { type: "brain_action", action: "update", resource: "task" },
 61→  { type: "brain_action", action: "update", resource: "session" },
 62→  { type: "brain_action", action: "update", resource: "suggestion" },
 63→  { type: "brain_action", action: "submit", resource: "intent" },
 64→];
 65→
 66→// ---------------------------------------------------------------------------
 67→// Port: Dependencies as function signatures
 68→// ---------------------------------------------------------------------------
 69→
 70→export type OrchestratorRouteDeps = {
 71→  createSession: (
 72→    workspaceId: string,
 73→    taskId: string,
 74→    authToken: string,
 75→  ) => Promise<OrchestratorSessionResult>;
 76→  getSessionStatus: (sessionId: string) => Promise<SessionStatusResult>;
 77→  abortSession: (sessionId: string) => Promise<AbortSessionResult>;
 78→  acceptSession: (
 79→    sessionId: string,
 80→    summary: string,
 81→  ) => Promise<AcceptSessionResult>;
 82→  getReview: (sessionId: string) => Promise<ReviewResult>;
 83→  rejectSession: (
 84→    sessionId: string,
 85→    feedback: string,
 86→  ) => Promise<RejectSessionResult>;
 87→  sendPrompt: (
 88→    sessionId: string,
 89→    text: string,
 90→  ) => Promise<PromptSessionResult>;
 91→};
 92→
 93→// ---------------------------------------------------------------------------
 94→// Request body parsing
 95→// ---------------------------------------------------------------------------
 96→
 97→type AssignBody = { taskId?: string };
 98→type AcceptBody = { summary?: string };
 99→type RejectBody = { feedback?: string };
100→type PromptBody = { text?: string };
101→
102→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
103→  try {
104→    return (await request.json()) as T;
105→  } catch {
106→    return undefined;
107→  }
108→}
109→
110→function extractAuthToken(request: Request): string {
111→  return request.headers.get("Cookie") ?? "";
112→}
113→
114→// ---------------------------------------------------------------------------
115→// Response builders (pure)
116→// ---------------------------------------------------------------------------
117→
118→function assignResponse(
119→  workspaceId: string,
120→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
121→): Response {
122→  return jsonResponse(
123→    {
124→      agentSessionId: value.agentSessionId,
125→      streamId: value.streamId,
126→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
127→    },
128→    200,
129→  );
130→}
131→
132→function statusResponse(
133→  sessionId: string,
134→  value: {
135→    orchestratorStatus: string;
136→    worktreeBranch?: string;
137→    worktreePath?: string;
138→    startedAt?: string;
139→    lastEventAt?: string;
140→    error?: string;
141→  },
142→): Response {
143→  return jsonResponse(
144→    {
145→      agentSessionId: sessionId,
146→      orchestratorStatus: value.orchestratorStatus,
147→      ...pickDefined({
148→        worktreeBranch: value.worktreeBranch,
149→        worktreePath: value.worktreePath,
150→        startedAt: value.startedAt,
151→        lastEventAt: value.lastEventAt,
152→        error: value.error,
153→      }),
154→    },
155→    200,
156→  );
157→}
158→
159→function acceptResponse(): Response {
160→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
161→}
162→
163→function abortResponse(): Response {
164→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
165→}
166→
167→function reviewResponse(value: {
168→  taskTitle: string;
169→  diff: unknown;
170→  session: unknown;
171→}): Response {
172→  return jsonResponse(value, 200);
173→}
174→
175→function rejectResponse(): Response {
176→  return jsonResponse({ rejected: true, continuing: true }, 200);
177→}
178→
179→function promptResponse(): Response {
180→  return jsonResponse({ delivered: true }, 202);
181→}
182→
183→function sessionErrorResponse(error: {
184→  message: string;
185→  httpStatus: number;
186→}): Response {
187→  return jsonError(error.message, error.httpStatus);
188→}
189→
190→// ---------------------------------------------------------------------------
191→// Route handler factory
192→// ---------------------------------------------------------------------------
193→
194→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
195→  const assign: RouteHandler = async (request) => {
196→    const workspaceId = request.params.workspaceId;
197→    const body = await parseJsonBody<AssignBody>(request);
198→
199→    if (!body?.taskId) {
200→      return jsonError("taskId is required", 400);
201→    }
202→
203→    const authToken = extractAuthToken(request);
204→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return assignResponse(workspaceId, result.value);
211→  };
212→
213→  const status: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getSessionStatus(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return statusResponse(sessionId, result.value);
222→  };
223→
224→  const accept: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<AcceptBody>(request);
227→    const summary = body?.summary ?? "";
228→
229→    const result = await deps.acceptSession(sessionId, summary);
230→
231→    if (!result.ok) {
232→      return sessionErrorResponse(result.error);
233→    }
234→
235→    return acceptResponse();
236→  };
237→
238→  const abort: RouteHandler = async (request) => {
239→    const sessionId = request.params.sessionId;
240→    const result = await deps.abortSession(sessionId);
241→
242→    if (!result.ok) {
243→      return sessionErrorResponse(result.error);
244→    }
245→
246→    return abortResponse();
247→  };
248→
249→  const review: RouteHandler = async (request) => {
250→    const sessionId = request.params.sessionId;
251→    const result = await deps.getReview(sessionId);
252→
253→    if (!result.ok) {
254→      return sessionErrorResponse(result.error);
255→    }
256→
257→    return reviewResponse(result.value);
258→  };
259→
260→  const reject: RouteHandler = async (request) => {
261→    const sessionId = request.params.sessionId;
262→    const body = await parseJsonBody<RejectBody>(request);
263→
264→    if (!body?.feedback || body.feedback.trim() === "") {
265→      return jsonError("feedback is required", 400);
266→    }
267→
268→    const result = await deps.rejectSession(sessionId, body.feedback);
269→
270→    if (!result.ok) {
271→      return sessionErrorResponse(result.error);
272→    }
273→
274→    return rejectResponse();
275→  };
276→
277→  const prompt: RouteHandler = async (request) => {
278→    const sessionId = request.params.sessionId;
279→    const body = await parseJsonBody<PromptBody>(request);
280→
281→    if (!body?.text || body.text.trim() === "") {
282→      return jsonError("text is required", 400);
283→    }
284→
285→    const result = await deps.sendPrompt(sessionId, body.text);
286→
287→    if (!result.ok) {
288→      return sessionErrorResponse(result.error);
289→    }
290→
291→    return promptResponse();
292→  };
293→
294→  return { assign, status, accept, abort, review, reject, prompt };
295→}
296→
297→// ---------------------------------------------------------------------------
298→// SSE stream route handler factory
299→// ---------------------------------------------------------------------------
300→
301→export type StreamRouteDeps = {
302→  sseRegistry: SseRegistry;
303→};
304→
305→export function createStreamRouteHandler(deps: StreamRouteDeps) {
306→  const stream: RouteHandler = async (request) => {
307→    const sessionId = request.params.sessionId;
308→
309→    if (!sessionId) {
310→      return jsonError("sessionId is required", 400);
311→    }
312→
313→    const streamId = `stream-${sessionId}`;
314→    return deps.sseRegistry.handleStreamRequest(streamId);
315→  };
316→
317→  return { stream };
318→}
319→
320→// ---------------------------------------------------------------------------
321→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
322→// ---------------------------------------------------------------------------
323→
324→export type OrchestratorWiringDeps = {
325→  surreal: import("surrealdb").Surreal;
326→  shellExec: import("./worktree-manager").ShellExec;
327→  brainBaseUrl: string;
328→  extractionModel: import("../runtime/types").ServerDependencies["extractionModel"];
329→  asSigningKey: import("../oauth/as-key-management").AsSigningKey;
330→  sseRegistry?: SseRegistry;
331→  queryFn: import("./spawn-agent").QueryFn;
332→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
333→  mockAgent: boolean;
334→  sandboxAgentAdapter?: import("./sandbox-adapter").SandboxAgentAdapter;
335→  sandboxAgentType?: string;
336→};
337→
338→export function wireOrchestratorRoutes(
339→  wiringDeps: OrchestratorWiringDeps,
340→): {
341→  assign: RouteHandler;
342→  status: RouteHandler;
343→  accept: RouteHandler;
344→  abort: RouteHandler;
345→  review: RouteHandler;
346→  reject: RouteHandler;
347→  prompt: RouteHandler;
348→  stream?: RouteHandler;
349→} {
350→  const proxyTokenTtlDays = readProxyTokenTtlDays();
351→
352→  const issueProxyTokenForWorkspace = async (
353→    workspaceId: string,
354→    authToken: string,
355→  ): Promise<{ proxyToken: string; identityId: string }> => {
356→    const sessionHeaders = new Headers(authToken ? { Cookie: authToken } : undefined);
357→    const session = await wiringDeps.auth.api.getSession({ headers: sessionHeaders });
358→    const personId = session?.user?.id;
359→    if (!personId) {
360→      throw new Error("Failed to issue proxy token: authentication required");
361→    }
362→
363→    const personRecord = new RecordId("person", personId);
364→    const workspaceRecord = new RecordId("workspace", workspaceId);
365→    const [identityRows] = await wiringDeps.surreal.query<[Array<RecordId<"identity", string>>]>(
366→      `SELECT VALUE in FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
367→      { person: personRecord, ws: workspaceRecord },
368→    );
369→    const identityRecord = identityRows[0];
370→    if (!identityRecord) {
371→      throw new Error(`Failed to issue proxy token: workspace membership required for ${workspaceId}`);
372→    }
373→    const identityId = identityRecord.id as string;
374→
375→    const rawToken = generateProxyToken();
376→    const tokenHash = hashProxyToken(rawToken);
377→    const expiresAt = computeExpiresAt(proxyTokenTtlDays);
378→
379→    await wiringDeps.surreal.query(
380→      `BEGIN TRANSACTION;
381→       UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
382→       CREATE proxy_token CONTENT {
383→         token_hash: $hash,
384→         workspace: $ws,
385→         identity: $identity,
386→         expires_at: $expires,
387→         created_at: time::now(),
388→         revoked: false
389→       };
390→       COMMIT TRANSACTION;`,
391→      {
392→        hash: tokenHash,
393→        ws: workspaceRecord,
394→        identity: identityRecord,
395→        expires: expiresAt,
396→      },
397→    );
398→
399→    return { proxyToken: rawToken, identityId };
400→  };
