402→  const issueBrainMcpAuthEnv = async (
403→    workspaceId: string,
404→    identityId: string,
405→    intentGoal: string,
406→    intentReasoning: string,
407→  ): Promise<Record<string, string>> => {
408→    const dpopKeys = await generateKeyPair();
409→    const intentResult = await submitIntentForAuthorization(
410→      {
411→        workspace_id: workspaceId,
412→        identity_id: identityId,
413→        authorization_details: CLI_AUTHORIZATION_DETAILS,
414→        dpop_jwk_thumbprint: dpopKeys.thumbprint,
415→        goal: intentGoal,
416→        reasoning: intentReasoning,
417→      },
418→      {
419→        surreal: wiringDeps.surreal,
420→        extractionModel: wiringDeps.extractionModel,
421→      },
422→    );
423→
424→    let intentStatus: string = intentResult.status;
425→    if (intentStatus === "pending_auth") {
426→      const evaluation = await evaluatePendingIntent(
427→        intentResult.intentId,
428→        {
429→          surreal: wiringDeps.surreal,
430→          extractionModel: wiringDeps.extractionModel,
431→          llmEvaluator: async () => ({
432→            decision: "APPROVE",
433→            risk_score: 0,
434→            reason: "Approved from explicit authenticated orchestrator task assignment",
435→            reasoning:
436→              "User explicitly assigned this task in the orchestrator UI. " +
437→              "Bootstrap MCP token is required to complete the assigned task.",
438→          }),
439→        },
440→      );
441→      if (!evaluation.ok) {
442→        throw new Error(
443→          `Failed to evaluate MCP auth intent: ${evaluation.httpStatus} ${evaluation.error}`,
444→        );
445→      }
446→      intentStatus = evaluation.value.status;
447→    }
448→
449→    if (intentStatus !== "authorized") {
450→      throw new Error(`MCP auth intent is "${intentStatus}" (expected "authorized")`);
451→    }
452→
453→    const tokenResult = await exchangeIntentForToken({
454→      surreal: wiringDeps.surreal,
455→      asSigningKey: wiringDeps.asSigningKey,
456→      intentId: intentResult.intentId,
457→      authorizationDetails: CLI_AUTHORIZATION_DETAILS,
458→      proofThumbprint: dpopKeys.thumbprint,
459→    });
460→
461→    if (!tokenResult.ok) {
462→      throw new Error(
463→        `Failed to exchange MCP auth token: ${tokenResult.httpStatus} ${tokenResult.errorDescription}`,
464→      );
465→    }
466→
467→    const dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenResult.value.expiresIn;
468→
469→    return {
470→      BRAIN_CLIENT_ID: "orchestrator-session",
471→      BRAIN_ACCESS_TOKEN: "orchestrator-session",
472→      BRAIN_REFRESH_TOKEN: "orchestrator-session",
473→      BRAIN_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
474→      BRAIN_DPOP_PRIVATE_JWK: JSON.stringify(dpopKeys.privateJwk),
475→      BRAIN_DPOP_PUBLIC_JWK: JSON.stringify(dpopKeys.publicJwk),
476→      BRAIN_DPOP_THUMBPRINT: dpopKeys.thumbprint,
477→      BRAIN_DPOP_ACCESS_TOKEN: tokenResult.value.accessToken,
478→      BRAIN_DPOP_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
479→    };
480→  };
481→
482→  // Workspace access guard — resolves user from session cookie, checks membership
483→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
484→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
485→    if (!session?.user?.id) {
486→      return jsonError("authentication required", 401);
487→    }
488→    const { RecordId } = await import("surrealdb");
489→    const personRecord = new RecordId("person", session.user.id);
490→    const workspaceRecord = new RecordId("workspace", workspaceId);
491→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
492→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
493→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
494→      { person: personRecord, ws: workspaceRecord },
495→    );
496→    if (!memberRows || memberRows.length === 0) {
497→      return jsonError("not a member of this workspace", 403);
498→    }
499→    return undefined;
500→  };
501→
502→  // Lazy imports to keep module boundary clean
503→  const lifecycleImport = import("./session-lifecycle");
504→  const queriesImport = import("../mcp/mcp-queries");
505→  const guardImport = import("./assignment-guard");
506→  const stallDetectorImport = import("./stall-detector");
507→
