521→  const buildTaskScopedIntentContext = async (
522→    taskId: string,
523→  ): Promise<{ goal: string; reasoning: string }> => {
524→    const taskRecord = new RecordId("task", taskId);
525→    const [taskRows] = await wiringDeps.surreal.query<[Array<{ title?: string; description?: string }>]>(
526→      `SELECT title, description FROM $task LIMIT 1;`,
527→      { task: taskRecord },
528→    );
529→    const taskTitle = taskRows[0]?.title?.trim();
530→    const taskDescription = taskRows[0]?.description?.trim();
531→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
532→    const descriptionSuffix = taskDescription && taskDescription.length > 0
533→      ? ` Task description: ${taskDescription}`
534→      : "";
535→
536→    return {
537→      goal: `Complete task: ${taskLabel}`,
538→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
539→    };
