781→        adapter,
782→      });
783→    },
784→  };
785→
786→  const handlers = createOrchestratorRouteHandlers(routeDeps);
787→
788→  // Wrap handler with workspace access check
789→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
790→    const workspaceId = request.params.workspaceId;
791→    if (workspaceId) {
792→      const accessError = await validateWorkspaceAccess(request, workspaceId);
793→      if (accessError) return accessError;
794→    }
795→    return handler(request);
796→  };
797→
798→  const streamHandler = wiringDeps.sseRegistry
799→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
800→    : undefined;
801→
802→  return {
803→    assign: withTracing("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
804→    status: withTracing("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
805→    accept: withTracing("orchestrator.accept", "POST", withWorkspaceAccess(handlers.accept)),
806→    abort: withTracing("orchestrator.abort", "POST", withWorkspaceAccess(handlers.abort)),
807→    review: withTracing("orchestrator.review", "GET", withWorkspaceAccess(handlers.review)),
808→    reject: withTracing("orchestrator.reject", "POST", withWorkspaceAccess(handlers.reject)),
809→    prompt: withTracing("orchestrator.prompt", "POST", withWorkspaceAccess(handlers.prompt)),
810→    ...(streamHandler
811→      ? { stream: withTracing("orchestrator.stream", "GET", withWorkspaceAccess(streamHandler.stream)) }
812→      : {}),
813→  };
814→}
