117→export type EventIterationDeps = {
118→  emitEvent: (streamId: string, event: StreamEvent) => void;
119→  updateSessionStatus: (
120→    sessionId: string,
121→    status: OrchestratorStatus,
122→    error?: string,
123→  ) => Promise<void>;
124→  updateLastEventAt: (sessionId: string) => Promise<void>;
125→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
126→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
127→};
128→
129→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
130→  TERMINAL_ORCHESTRATOR_STATUSES,
131→);
132→
133→/**
134→ * Iterates the SDK message stream, forwarding messages through the event
135→ * bridge. Transitions session to "active" on first message, starts stall
136→ * detection, and stops on terminal status or error.
137→ *
138→ * Returns a Promise that resolves when iteration ends (for testing).
139→ * In production, this is launched fire-and-forget.
140→ */
141→export function startEventIteration(
142→  deps: EventIterationDeps,
143→  messageStream: AsyncIterable<unknown>,
144→  streamId: string,
145→  sessionId: string,
146→): Promise<void> {
147→  const stallDetector = deps.startStallDetector(sessionId, streamId);
148→
149→  const bridge = startEventBridge(
150→    {
151→      emitEvent: deps.emitEvent,
152→      updateLastEventAt: deps.updateLastEventAt,
153→    },
154→    streamId,
155→    sessionId,
156→    stallDetector,
157→  );
158→
159→  let firstMessageReceived = false;
160→  let messageCount = 0;
161→
162→  async function iterate(): Promise<void> {
163→    log.info("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
164→    try {
165→      for await (const rawMessage of messageStream) {
166→        messageCount++;
167→        const msg = rawMessage as SdkMessage;
168→        log.info("orchestrator.iteration", `SDK message received (#${messageCount})`, {
169→          sessionId,
170→          messageType: msg.type,
171→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
172→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
173→        });
174→
175→        // Check if session has reached terminal status
176→        const currentStatus = await deps.getSessionStatus(sessionId);
177→        if (TERMINAL_STATUSES.has(currentStatus)) {
178→          log.info("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
179→          break;
180→        }
181→
182→        // Transition to active on first message
183→        if (!firstMessageReceived) {
184→          firstMessageReceived = true;
185→          await deps.updateSessionStatus(sessionId, "active");
186→        }
187→
188→        // Forward through event bridge (transform + emit + stall detection)
189→        bridge.handleMessage(msg);
190→      }
191→      log.info("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
192→      // Transition to idle when stream ends normally and agent produced output
193→      if (firstMessageReceived) {
194→        const finalStatus = await deps.getSessionStatus(sessionId);
195→        if (!TERMINAL_STATUSES.has(finalStatus)) {
196→          await deps.updateSessionStatus(sessionId, "idle");
197→        }
198→      }
199→    } catch (err) {
200→      const errorMessage = err instanceof Error ? err.message : String(err);

