36→// ---------------------------------------------------------------------------
37→
38→export type AssignmentValidation = {
39→  taskRecord: RecordId<"task", string>;
40→  workspaceRecord: RecordId<"workspace", string>;
41→  taskStatus: AssignableTaskStatus;
42→  title: string;
43→  repoPath: string;
