 85→    feedback: string,
 86→  ) => Promise<RejectSessionResult>;
 87→  sendPrompt: (
 88→    sessionId: string,
 89→    text: string,
 90→  ) => Promise<PromptSessionResult>;
 91→};
 92→
 93→// ---------------------------------------------------------------------------
 94→// Request body parsing
 95→// ---------------------------------------------------------------------------
 96→
 97→type AssignBody = { taskId?: string };
 98→type AcceptBody = { summary?: string };
 99→type RejectBody = { feedback?: string };
100→type PromptBody = { text?: string };
101→
102→async function parseJsonBody<T>(request: Request): Promise<T | undefined> {
103→  try {
104→    return (await request.json()) as T;
105→  } catch {
106→    return undefined;
107→  }
108→}
109→
110→function extractAuthToken(request: Request): string {
111→  return request.headers.get("Cookie") ?? "";
112→}
113→
114→// ---------------------------------------------------------------------------
115→// Response builders (pure)
116→// ---------------------------------------------------------------------------
117→
118→function assignResponse(
119→  workspaceId: string,
120→  value: { agentSessionId: string; streamId: string; worktreeBranch: string },
121→): Response {
122→  return jsonResponse(
123→    {
124→      agentSessionId: value.agentSessionId,
125→      streamId: value.streamId,
126→      streamUrl: `/api/orchestrator/${workspaceId}/sessions/${value.agentSessionId}/stream`,
127→    },
128→    200,
129→  );
130→}
131→
132→function statusResponse(
133→  sessionId: string,
134→  value: {
135→    orchestratorStatus: string;
136→    worktreeBranch?: string;
137→    worktreePath?: string;
138→    startedAt?: string;
139→    lastEventAt?: string;
140→    error?: string;
141→  },
142→): Response {
143→  return jsonResponse(
144→    {
145→      agentSessionId: sessionId,
146→      orchestratorStatus: value.orchestratorStatus,
147→      ...pickDefined({
148→        worktreeBranch: value.worktreeBranch,
149→        worktreePath: value.worktreePath,
150→        startedAt: value.startedAt,
151→        lastEventAt: value.lastEventAt,
152→        error: value.error,
153→      }),
154→    },
155→    200,
156→  );
157→}
158→
159→function acceptResponse(): Response {
160→  return jsonResponse({ accepted: true, taskStatus: "done" }, 200);
161→}
162→
163→function abortResponse(): Response {
164→  return jsonResponse({ aborted: true, taskStatus: "ready" }, 200);
165→}
166→
167→function reviewResponse(value: {
168→  taskTitle: string;
169→  diff: unknown;
170→  session: unknown;
171→}): Response {
172→  return jsonResponse(value, 200);
173→}
174→
175→function rejectResponse(): Response {
176→  return jsonResponse({ rejected: true, continuing: true }, 200);
177→}
178→
179→function promptResponse(): Response {
180→  return jsonResponse({ delivered: true }, 202);
181→}
182→
183→function sessionErrorResponse(error: {
184→  message: string;
185→  httpStatus: number;
186→}): Response {
187→  return jsonError(error.message, error.httpStatus);
188→}
189→
190→// ---------------------------------------------------------------------------
191→// Route handler factory
192→// ---------------------------------------------------------------------------
193→
194→export function createOrchestratorRouteHandlers(deps: OrchestratorRouteDeps) {
195→  const assign: RouteHandler = async (request) => {
196→    const workspaceId = request.params.workspaceId;
197→    const body = await parseJsonBody<AssignBody>(request);
198→
199→    if (!body?.taskId) {
200→      return jsonError("taskId is required", 400);
201→    }
202→
203→    const authToken = extractAuthToken(request);
204→    const result = await deps.createSession(workspaceId, body.taskId, authToken);
205→
206→    if (!result.ok) {
207→      return sessionErrorResponse(result.error);
208→    }
209→
210→    return assignResponse(workspaceId, result.value);
211→  };
212→
213→  const status: RouteHandler = async (request) => {
214→    const sessionId = request.params.sessionId;
215→    const result = await deps.getSessionStatus(sessionId);
216→
217→    if (!result.ok) {
218→      return sessionErrorResponse(result.error);
219→    }
220→
221→    return statusResponse(sessionId, result.value);
222→  };
223→
224→  const accept: RouteHandler = async (request) => {
225→    const sessionId = request.params.sessionId;
226→    const body = await parseJsonBody<AcceptBody>(request);
227→    const summary = body?.summary ?? "";
228→
229→    const result = await deps.acceptSession(sessionId, summary);
230→
231→    if (!result.ok) {
232→      return sessionErrorResponse(result.error);
233→    }
234→
235→    return acceptResponse();
236→  };
237→
238→  const abort: RouteHandler = async (request) => {
239→    const sessionId = request.params.sessionId;
240→    const result = await deps.abortSession(sessionId);
241→
242→    if (!result.ok) {
243→      return sessionErrorResponse(result.error);
244→    }
245→
246→    return abortResponse();
247→  };
248→
249→  const review: RouteHandler = async (request) => {
250→    const sessionId = request.params.sessionId;
251→    const result = await deps.getReview(sessionId);
252→
253→    if (!result.ok) {
254→      return sessionErrorResponse(result.error);
255→    }
256→
257→    return reviewResponse(result.value);
258→  };
259→
260→  const reject: RouteHandler = async (request) => {
261→    const sessionId = request.params.sessionId;
262→    const body = await parseJsonBody<RejectBody>(request);
263→
264→    if (!body?.feedback || body.feedback.trim() === "") {
265→      return jsonError("feedback is required", 400);
266→    }
267→
268→    const result = await deps.rejectSession(sessionId, body.feedback);
269→
270→    if (!result.ok) {
271→      return sessionErrorResponse(result.error);
272→    }
273→
274→    return rejectResponse();
275→  };
276→
277→  const prompt: RouteHandler = async (request) => {
278→    const sessionId = request.params.sessionId;
279→    const body = await parseJsonBody<PromptBody>(request);
280→
281→    if (!body?.text || body.text.trim() === "") {
282→      return jsonError("text is required", 400);
283→    }
284→
285→    const result = await deps.sendPrompt(sessionId, body.text);
286→
287→    if (!result.ok) {
288→      return sessionErrorResponse(result.error);
289→    }
290→
291→    return promptResponse();
292→  };
293→
294→  return { assign, status, accept, abort, review, reject, prompt };
295→}
296→
297→// ---------------------------------------------------------------------------
298→// SSE stream route handler factory
299→// ---------------------------------------------------------------------------
300→
301→export type StreamRouteDeps = {
302→  sseRegistry: SseRegistry;
303→};
304→
305→export function createStreamRouteHandler(deps: StreamRouteDeps) {
306→  const stream: RouteHandler = async (request) => {
307→    const sessionId = request.params.sessionId;
308→
309→    if (!sessionId) {
310→      return jsonError("sessionId is required", 400);
311→    }
312→
313→    const streamId = `stream-${sessionId}`;
314→    return deps.sseRegistry.handleStreamRequest(streamId);
315→  };
316→
317→  return { stream };
318→}
319→
320→// ---------------------------------------------------------------------------
321→// Wiring factory: creates OrchestratorRouteDeps from server dependencies
322→// ---------------------------------------------------------------------------
323→
324→export type OrchestratorWiringDeps = {
325→  surreal: import("surrealdb").Surreal;
326→  shellExec: import("./worktree-manager").ShellExec;
327→  brainBaseUrl: string;
328→  extractionModel: import("../runtime/types").ServerDependencies["extractionModel"];
329→  asSigningKey: import("../oauth/as-key-management").AsSigningKey;
330→  sseRegistry?: SseRegistry;
331→  auth: { api: { getSession: (opts: { headers: Headers }) => Promise<{ user?: { id?: string } } | null> } };
332→  mockAgent: boolean;
333→  sandboxAgentAdapter?: import("./sandbox-adapter").SandboxAgentAdapter;
334→  sandboxAgentType?: string;
335→};
336→
337→export function wireOrchestratorRoutes(
338→  wiringDeps: OrchestratorWiringDeps,
339→): {
340→  assign: RouteHandler;
341→  status: RouteHandler;
342→  accept: RouteHandler;
343→  abort: RouteHandler;
344→  review: RouteHandler;
345→  reject: RouteHandler;
346→  prompt: RouteHandler;
347→  stream?: RouteHandler;
348→} {
349→  const proxyTokenTtlDays = readProxyTokenTtlDays();
350→
351→  const issueProxyTokenForWorkspace = async (
352→    workspaceId: string,
353→    authToken: string,
354→  ): Promise<{ proxyToken: string; identityId: string }> => {
355→    const sessionHeaders = new Headers(authToken ? { Cookie: authToken } : undefined);
356→    const session = await wiringDeps.auth.api.getSession({ headers: sessionHeaders });
357→    const personId = session?.user?.id;
358→    if (!personId) {
359→      throw new Error("Failed to issue proxy token: authentication required");
360→    }
361→
362→    const personRecord = new RecordId("person", personId);
363→    const workspaceRecord = new RecordId("workspace", workspaceId);
364→    const [identityRows] = await wiringDeps.surreal.query<[Array<RecordId<"identity", string>>]>(
365→      `SELECT VALUE in FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
366→      { person: personRecord, ws: workspaceRecord },
367→    );
368→    const identityRecord = identityRows[0];
369→    if (!identityRecord) {
370→      throw new Error(`Failed to issue proxy token: workspace membership required for ${workspaceId}`);
371→    }
372→    const identityId = identityRecord.id as string;
373→
374→    const rawToken = generateProxyToken();
375→    const tokenHash = hashProxyToken(rawToken);
376→    const expiresAt = computeExpiresAt(proxyTokenTtlDays);
377→
378→    await wiringDeps.surreal.query(
379→      `BEGIN TRANSACTION;
380→       UPDATE proxy_token SET revoked = true WHERE identity = $identity AND workspace = $ws AND revoked = false;
381→       CREATE proxy_token CONTENT {
382→         token_hash: $hash,
383→         workspace: $ws,
384→         identity: $identity,
385→         expires_at: $expires,
386→         created_at: time::now(),
387→         revoked: false
388→       };
389→       COMMIT TRANSACTION;`,
390→      {
391→        hash: tokenHash,
392→        ws: workspaceRecord,
393→        identity: identityRecord,
394→        expires: expiresAt,
395→      },
396→    );
397→
398→    return { proxyToken: rawToken, identityId };
399→  };
400→
401→  const issueBrainMcpAuthEnv = async (
402→    workspaceId: string,
403→    identityId: string,
404→    intentGoal: string,
405→    intentReasoning: string,
406→  ): Promise<Record<string, string>> => {
407→    const dpopKeys = await generateKeyPair();
408→    const intentResult = await submitIntentForAuthorization(
409→      {
410→        workspace_id: workspaceId,
411→        identity_id: identityId,
412→        authorization_details: CLI_AUTHORIZATION_DETAILS,
413→        dpop_jwk_thumbprint: dpopKeys.thumbprint,
414→        goal: intentGoal,
415→        reasoning: intentReasoning,
416→      },
417→      {
418→        surreal: wiringDeps.surreal,
419→        extractionModel: wiringDeps.extractionModel,
420→      },
421→    );
422→
423→    let intentStatus: string = intentResult.status;
424→    if (intentStatus === "pending_auth") {
425→      const evaluation = await evaluatePendingIntent(
426→        intentResult.intentId,
427→        {
428→          surreal: wiringDeps.surreal,
429→          extractionModel: wiringDeps.extractionModel,
430→          llmEvaluator: async () => ({
431→            decision: "APPROVE",
432→            risk_score: 0,
433→            reason: "Approved from explicit authenticated orchestrator task assignment",
434→            reasoning:
435→              "User explicitly assigned this task in the orchestrator UI. " +
436→              "Bootstrap MCP token is required to complete the assigned task.",
437→          }),
438→        },
439→      );
440→      if (!evaluation.ok) {
441→        throw new Error(
442→          `Failed to evaluate MCP auth intent: ${evaluation.httpStatus} ${evaluation.error}`,
443→        );
444→      }
445→      intentStatus = evaluation.value.status;
446→    }
447→
448→    if (intentStatus !== "authorized") {
449→      throw new Error(`MCP auth intent is "${intentStatus}" (expected "authorized")`);
450→    }
451→
452→    const tokenResult = await exchangeIntentForToken({
453→      surreal: wiringDeps.surreal,
454→      asSigningKey: wiringDeps.asSigningKey,
455→      intentId: intentResult.intentId,
456→      authorizationDetails: CLI_AUTHORIZATION_DETAILS,
457→      proofThumbprint: dpopKeys.thumbprint,
458→    });
459→
460→    if (!tokenResult.ok) {
461→      throw new Error(
462→        `Failed to exchange MCP auth token: ${tokenResult.httpStatus} ${tokenResult.errorDescription}`,
463→      );
464→    }
465→
466→    const dpopTokenExpiresAt = Math.floor(Date.now() / 1000) + tokenResult.value.expiresIn;
467→
468→    return {
469→      BRAIN_CLIENT_ID: "orchestrator-session",
470→      BRAIN_ACCESS_TOKEN: "orchestrator-session",
471→      BRAIN_REFRESH_TOKEN: "orchestrator-session",
472→      BRAIN_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
473→      BRAIN_DPOP_PRIVATE_JWK: JSON.stringify(dpopKeys.privateJwk),
474→      BRAIN_DPOP_PUBLIC_JWK: JSON.stringify(dpopKeys.publicJwk),
475→      BRAIN_DPOP_THUMBPRINT: dpopKeys.thumbprint,
476→      BRAIN_DPOP_ACCESS_TOKEN: tokenResult.value.accessToken,
477→      BRAIN_DPOP_TOKEN_EXPIRES_AT: String(dpopTokenExpiresAt),
478→    };
479→  };
480→
481→  // Workspace access guard — resolves user from session cookie, checks membership
482→  const validateWorkspaceAccess = async (request: Request, workspaceId: string): Promise<Response | undefined> => {
483→    const session = await wiringDeps.auth.api.getSession({ headers: request.headers });
484→    if (!session?.user?.id) {
485→      return jsonError("authentication required", 401);
486→    }
487→    const { RecordId } = await import("surrealdb");
488→    const personRecord = new RecordId("person", session.user.id);
489→    const workspaceRecord = new RecordId("workspace", workspaceId);
490→    // member_of is identity->workspace; resolve person->identity via identity_person subquery
491→    const [memberRows] = await wiringDeps.surreal.query<[Array<{ role: string }>]>(
492→      `SELECT role FROM member_of WHERE in IN (SELECT VALUE in FROM identity_person WHERE out = $person) AND out = $ws LIMIT 1;`,
493→      { person: personRecord, ws: workspaceRecord },
494→    );
495→    if (!memberRows || memberRows.length === 0) {
496→      return jsonError("not a member of this workspace", 403);
497→    }
498→    return undefined;
499→  };
500→
501→  // Lazy imports to keep module boundary clean
502→  const lifecycleImport = import("./session-lifecycle");
503→  const queriesImport = import("../mcp/mcp-queries");
504→  const guardImport = import("./assignment-guard");
505→  const stallDetectorImport = import("./stall-detector");
506→
507→  // Helper: resolve repo_path from workspace record
508→  const resolveRepoRoot = async (workspaceRecord: import("surrealdb").RecordId<"workspace", string>): Promise<string> => {
509→    const [rows] = await wiringDeps.surreal.query<[Array<{ repo_path?: string }>]>(
510→      `SELECT repo_path FROM $ws;`,
511→      { ws: workspaceRecord },
512→    );
513→    const repoPath = rows[0]?.repo_path;
514→    if (!repoPath) {
515→      throw new Error(`Workspace ${workspaceRecord.id} has no repo_path configured`);
516→    }
517→    return repoPath;
518→  };
519→
520→  const buildTaskScopedIntentContext = async (
521→    taskId: string,
522→  ): Promise<{ goal: string; reasoning: string }> => {
523→    const taskRecord = new RecordId("task", taskId);
524→    const [taskRows] = await wiringDeps.surreal.query<[Array<{ title?: string; description?: string }>]>(
525→      `SELECT title, description FROM $task LIMIT 1;`,
526→      { task: taskRecord },
527→    );
528→    const taskTitle = taskRows[0]?.title?.trim();
529→    const taskDescription = taskRows[0]?.description?.trim();
530→    const taskLabel = taskTitle && taskTitle.length > 0 ? taskTitle : taskId;
531→    const descriptionSuffix = taskDescription && taskDescription.length > 0
532→      ? ` Task description: ${taskDescription}`
533→      : "";
534→
535→    return {
536→      goal: `Complete task: ${taskLabel}`,
537→      reasoning: `Use Brain MCP tools required to complete task "${taskLabel}" in this workspace.${descriptionSuffix}`,
538→    };
539→  };
540→
541→  // Resolve adapter: real SDK adapter from deps, or mock for tests
542→  const sandboxAdapterPromise = wiringDeps.sandboxAgentAdapter
543→    ? Promise.resolve(wiringDeps.sandboxAgentAdapter)
544→    : wiringDeps.mockAgent
545→      ? import("./sandbox-adapter").then((mod) => mod.createMockAdapter())
546→      : Promise.reject(new Error("No sandbox adapter configured — set sandboxAgentAdapter or mockAgent"));
547→
548→  const routeDeps: OrchestratorRouteDeps = {
549→    createSession: async (workspaceId, taskId, _authToken) => {
550→      const [adapter, lifecycle, queries, guard, stallDetector] = await Promise.all([
551→        sandboxAdapterPromise,
552→        lifecycleImport,
553→        queriesImport,
554→        guardImport,
555→        stallDetectorImport,
556→      ]);
557→
558→      const result = await lifecycle.createOrchestratorSession({
559→        surreal: wiringDeps.surreal,
560→        shellExec: wiringDeps.shellExec,
561→        brainBaseUrl: wiringDeps.brainBaseUrl,
562→        workspaceId,
563→        taskId,
564→        validateAssignment: guard.validateAssignment,
565→        createAgentSession: queries.createAgentSession,
566→        adapter,
567→        sandboxAgentType: wiringDeps.sandboxAgentType,
568→      });
569→
570→      // Wire SSE stream + event iteration on success
571→      if (result.ok && wiringDeps.sseRegistry) {
572→        const { agentSessionId, streamId, sessionHandle } = result.value;
573→        wiringDeps.sseRegistry.registerMessage(streamId);
574→
575→        // Adapter path: wire sandbox event bridge
576→        if (sessionHandle && adapter) {
577→          const { createSandboxEventBridge } = await import("./sandbox-event-bridge");
578→          const bridge = createSandboxEventBridge(
579→            {
580→              emitEvent: wiringDeps.sseRegistry.emitEvent,
581→              updateLastEventAt: async (sid) => {
582→                const rec = new RecordId("agent_session", sid);
583→                await wiringDeps.surreal.update(rec).merge({
584→                  last_event_at: new Date(),
585→                });
586→              },
587→              notifyStallDetector: () => {
588→                // Stall detector integration deferred to later step
589→              },
590→            },
591→            streamId,
592→            agentSessionId,
593→          );
594→          sessionHandle.onEvent((event) => {
595→            bridge.handleEvent(event as import("./sandbox-event-bridge").SandboxEvent);
596→          });
597→        } else {
598→          // Legacy path: SDK message stream iteration
599→          const handle = lifecycle.getHandle(agentSessionId);
600→          if (handle) {
601→            const { RecordId } = await import("surrealdb");
602→            lifecycle.startEventIteration(
603→              {
604→                emitEvent: wiringDeps.sseRegistry.emitEvent,
605→                updateSessionStatus: async (sid, status, error) => {
606→                  const rec = new RecordId("agent_session", sid);
607→                  await wiringDeps.surreal.update(rec).merge({
608→                    orchestrator_status: status,
609→                    ...(error !== undefined ? { error_message: error } : {}),
610→                  });
611→                },
612→                updateLastEventAt: async (sid) => {
613→                  const rec = new RecordId("agent_session", sid);
614→                  await wiringDeps.surreal.update(rec).merge({
615→                    last_event_at: new Date(),
616→                  });
617→                },
618→                getSessionStatus: async (sid) => {
619→                  const rec = new RecordId("agent_session", sid);
620→                  const row = await wiringDeps.surreal.select(rec) as { orchestrator_status?: string } | undefined;
621→                  return (row?.orchestrator_status ?? "error") as import("./types").OrchestratorStatus;
622→                },
623→                startStallDetector: (sid, stId) =>
624→                  stallDetector.startStallDetector(
625→                    {
626→                      abortSession: async (abortSid) => {
627→                        const abortResult = await lifecycle.abortOrchestratorSession({
628→                          surreal: wiringDeps.surreal,
629→                          shellExec: wiringDeps.shellExec,
630→                          resolveRepoRoot,
631→                          sessionId: abortSid,
632→                          endAgentSession: queries.endAgentSession,
633→                        });
634→                        return abortResult;
635→                      },
636→                      createObservation: async () => {},
637→                      emitEvent: wiringDeps.sseRegistry!.emitEvent,
638→                    },
639→                    stallDetector.DEFAULT_STALL_CONFIG,
640→                    sid,
641→                    stId,
642→                  ),
643→              },
644→              handle.messages,
645→              streamId,
646→              agentSessionId,
647→            );
648→          }
649→        }
650→      }
651→
652→      return result;
653→    },
654→
655→    getSessionStatus: async (sessionId) => {
656→      const lifecycle = await lifecycleImport;
657→      return lifecycle.getOrchestratorSessionStatus({
658→        surreal: wiringDeps.surreal,
659→        sessionId,
660→      });
661→    },
662→
663→    abortSession: async (sessionId) => {
664→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
665→      const [lifecycle, queries] = await Promise.all([
666→        lifecycleImport,
667→        queriesImport,
668→      ]);
669→      return lifecycle.abortOrchestratorSession({
670→        surreal: wiringDeps.surreal,
671→        shellExec: wiringDeps.shellExec,
672→        resolveRepoRoot,
673→        sessionId,
674→        adapter,
675→        endAgentSession: queries.endAgentSession,
676→      });
677→    },
678→
679→    acceptSession: async (sessionId, summary) => {
680→      const [lifecycle, queries] = await Promise.all([
681→        lifecycleImport,
682→        queriesImport,
683→      ]);
684→      return lifecycle.acceptOrchestratorSession({
685→        surreal: wiringDeps.surreal,
686→        sessionId,
687→        summary,
688→        endAgentSession: queries.endAgentSession,
689→      });
690→    },
691→
692→    getReview: async (sessionId) => {
693→      const [lifecycle, worktreeManager] = await Promise.all([
694→        lifecycleImport,
695→        import("./worktree-manager"),
696→      ]);
697→      return lifecycle.getOrchestratorReview({
698→        surreal: wiringDeps.surreal,
699→        sessionId,
700→        resolveRepoRoot,
701→        getDiff: (repoRoot: string, branchName: string) =>
702→          worktreeManager.getDiff(wiringDeps.shellExec, repoRoot, branchName),
703→        getTaskTitle: async (taskId: string) => {
704→          const { RecordId } = await import("surrealdb");
705→          const taskRecord = new RecordId("task", taskId);
706→          const rows = (await wiringDeps.surreal.query(
707→            `SELECT title FROM $task;`,
708→            { task: taskRecord },
709→          )) as Array<Array<{ title: string }>>;
710→          return rows[0]?.[0]?.title ?? "";
711→        },
712→      });
713→    },
714→
715→    rejectSession: async (sessionId, feedback) => {
716→      const lifecycle = await lifecycleImport;
717→      return lifecycle.rejectOrchestratorSession({
718→        surreal: wiringDeps.surreal,
719→        sessionId,
720→        feedback,
721→      });
722→    },
723→
724→    sendPrompt: async (sessionId, text) => {
725→      const adapter = sandboxAdapterImport ? await sandboxAdapterImport : undefined;
726→      const lifecycle = await lifecycleImport;
727→      return lifecycle.sendSessionPrompt({
728→        surreal: wiringDeps.surreal,
729→        sessionId,
730→        text,
731→        adapter,
732→      });
733→    },
734→  };
735→
736→  const handlers = createOrchestratorRouteHandlers(routeDeps);
737→
738→  // Wrap handler with workspace access check
739→  const withWorkspaceAccess = (handler: RouteHandler): RouteHandler => async (request) => {
740→    const workspaceId = request.params.workspaceId;
741→    if (workspaceId) {
742→      const accessError = await validateWorkspaceAccess(request, workspaceId);
743→      if (accessError) return accessError;
744→    }
745→    return handler(request);
746→  };
747→
748→  const streamHandler = wiringDeps.sseRegistry
749→    ? createStreamRouteHandler({ sseRegistry: wiringDeps.sseRegistry })
750→    : undefined;
751→
752→  return {
753→    assign: withTracing("orchestrator.assign", "POST", withWorkspaceAccess(handlers.assign)),
754→    status: withTracing("orchestrator.status", "GET", withWorkspaceAccess(handlers.status)),
