609→};
610→
611→export async function acceptOrchestratorSession(
612→  input: AcceptSessionInput,
613→): Promise<AcceptSessionResult> {
614→  const lookup = await lookupSession(input.surreal, input.sessionId);
615→  if (!lookup.ok) {
616→    return { ok: false, error: lookup.error };
617→  }
618→  const { session, record: sessionRecord, status } = lookup;
619→
620→  if (!ACCEPTABLE_STATUSES.has(status)) {
621→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
622→  }
623→
624→  const workspaceRecord = requireWorkspace(session, input.sessionId);
625→
626→  // 1. Update orchestrator_status to completed
