          "test_file": "tests/unit/orchestrator/session-lifecycle.test.ts",
          "scenario_name": "SL-10, SL-11"
        },
        {
          "id": "05-04",
          "name": "Acceptance test: MCP endpoint serves filtered tools",
          "criteria": "AM-7: Create workspace with identity, grant 2 of 4 tools via can_use edges, spawn sandbox session, GET tools/list returns only 2 granted tools. AM-8: POST tools/call for unauthorized tool returns 403. AM-9: POST tools/call for authorized tool returns result and creates trace record.",
          "test_file": "tests/acceptance/sandbox-session-governance.test.ts",
          "scenario_name": "AM-7, AM-8, AM-9"
        }
      ]
    },
    {
      "id": "06",
      "name": "R2: Permission Handler and E2E Governance",
