input.new_string:
{
  "id": "05",
  "name": "R2: Dynamic Per-Agent MCP Endpoint with Intent-Gated Tools",
  "steps": [
    {
      "id": "05-01",
      "name": "Agent MCP endpoint: tools/list with policy-derived gating hints",
      "criteria": "New route GET /mcp/agent/:sessionId/tools/list. Auth via X-Brain-Auth (resolveProxyAuth → identity + session). Returns all can_use granted tools. For each tool, checks if it is covered by any authorized intent linked to session via gates edges. Ungated tools (no intent required by policy): returned as-is. Gated tools (policy requires intent): description enriched with gating hint instructing agent to create an intent with goal+reasoning via create_intent before calling. Unit tests: ungated tool description unchanged, gated tool description includes intent instructions, invalid token 401.",
      "test_file": "tests/unit/mcp/agent-mcp-route.test.ts",
      "scenario_name": "AM-1, AM-2, AM-3, AM-4"
    },
    {
      "id": "05-02",
      "name": "Agent MCP endpoint: tools/call with intent check, 403 escalation, and trace",
      "criteria": "New route POST /mcp/agent/:sessionId/tools/call. Resolves session from proxy token. For the requested tool, checks if policy requires an intent. If no intent required: forward directly to upstream MCP. If intent required: queries all intents linked to session via gates edges, checks requested tool+params against union of authorization_details. If covered: forward to upstream MCP. If not covered: return 403 JSON-RPC error with structured body { code: -32403, message: 'intent_required', data: { tool, action_spec_template } } so agent knows to create an intent. All successful calls create trace record. Unit tests: ungated tool forwards without intent check, gated+covered tool succeeds, gated+uncovered tool returns intent_required 403, trace created on success.",
      "test_file": "tests/unit/mcp/agent-mcp-route.test.ts",
      "scenario_name": "AM-5, AM-6, AM-7, AM-8"
    },
    {
      "id": "05-03",
      "name": "Agent MCP endpoint: create_intent and intent lifecycle tools",
      "criteria": "Agent MCP endpoint exposes Brain graph tools alongside upstream MCP tools: create_intent (with goal, reasoning, action_spec), get_intent_status, list_session_intents. create_intent runs the intent through policy gate and auto-approve/veto flow. On authorization, creates gates edge linking intent to session. Agent can poll get_intent_status to wait for human approval when in pending_veto. Unit tests: create_intent produces authorized intent with gates edge (auto-approve path), create_intent with veto-required policy produces pending_veto intent, get_intent_status returns current status.",
      "test_file": "tests/unit/mcp/agent-mcp-route.test.ts",
      "scenario_name": "AM-9, AM-10, AM-11, AM-12"
    },
    {
      "id": "05-04",
      "name": "Wire MCP endpoint URL into session spawn env",
      "criteria": "After proxy token issued, add BRAIN_MCP_URL (brainBaseUrl/mcp/agent/{sessionId}) to adapter env alongside ANTHROPIC_BASE_URL. Same X-Brain-Auth token authenticates both planes. Unit test verifies env includes both URLs with matching token.",
      "test_file": "tests/unit/orchestrator/session-lifecycle.test.ts",
      "scenario_name": "SL-10, SL-11"
    }
  ]
},
{
  "id": "06",
  "name": "R2: Agent-Driven Escalation E2E",
  "steps": [
    {
      "id": "06-01",
      "name": "Acceptance test: agent-driven intent escalation flow",
      "criteria": "ESC-1: Spawn session with 2 tools granted (1 ungated, 1 gated). tools/list returns both; gated tool description includes intent instructions. ESC-2: tools/call on ungated tool succeeds immediately without intent. ESC-3: tools/call on gated tool without intent returns 403 intent_required with action_spec_template. ESC-4: Agent calls create_intent with goal+reasoning+action_spec, intent auto-approved, gates edge created. ESC-5: Retry tools/call on gated tool now succeeds, trace record created. ESC-6: tools/list now shows gated tool without hint (intent covers it).",
      "test_file": "tests/acceptance/sandbox-session-governance.test.ts",
      "scenario_name": "ESC-1, ESC-2, ESC-3, ESC-4, ESC-5, ESC-6"
    },
    {
      "id": "06-02",
      "name": "Acceptance test: human veto window + E2E provenance",
      "criteria": "GOV-1: Spawn session, verify proxy URL + MCP URL in env. GOV-2: proxy_token has intent + session fields linking to initial intent. GOV-3: Agent calls create_intent for high-risk tool, policy routes to pending_veto, get_intent_status returns pending_veto. GOV-4: Human approves via existing intent approve endpoint, get_intent_status returns authorized, gates edge created. GOV-5: tools/call now succeeds. GOV-6: Full provenance chain: initial intent → gates → session, escalation intent → gates → session, proxy_token → initial intent, trace → tool call.",
      "test_file": "tests/acceptance/sandbox-session-governance.test.ts",
      "scenario_name": "GOV-1, GOV-2, GOV-3, GOV-4, GOV-5, GOV-6"
    }
  ]
}

