{
  "roadmap": {
    "project_id": "sandbox-agent-integration",
    "created_at": "2026-03-25T06:32:34Z",
    "total_steps": 18,
    "phases": 6
  },
  "phases": [
    {
      "id": "01",
      "name": "Foundation: Types, Adapter, Event Bridge",
      "steps": [
        {
          "id": "01-01",
          "name": "Adapter port types and mock adapter",
          "criteria": "Adapter and session handle port types are defined. Mock factory exists for test injection. All UA-1..6 unit tests pass.",
          "test_file": "tests/unit/orchestrator/sandbox-adapter.test.ts",
          "scenario_name": "UA-1, UA-2, UA-3, UA-4, UA-5, UA-6"
        },
        {
          "id": "01-02",
          "name": "Event bridge translation functions",
          "criteria": "Event bridge translates SandboxAgent events to Brain StreamEvent variants. Unknown events are logged and skipped. All UB-1..7 unit tests pass.",
          "test_file": "tests/unit/orchestrator/sandbox-event-bridge.test.ts",
          "scenario_name": "UB-1, UB-2, UB-3, UB-4, UB-5, UB-6, UB-7"
        },
        {
          "id": "01-03",
          "name": "StreamEvent types and schema migration",
          "criteria": "StreamEvent union extended with permission request variant. Schema migration adds provider and session type fields. bun migrate succeeds. UC-1..5 validate field presence.",
          "test_file": "tests/unit/orchestrator/session-store.test.ts",
          "scenario_name": "UC-1, UC-2, UC-3, UC-4, UC-5"
        }
      ]
    },
    {
      "id": "02",
      "name": "Session Store and Lifecycle Refactor",
      "steps": [
        {
          "id": "02-01",
          "name": "Session store SurrealDB CRUD",
          "criteria": "Session store provides create, status update, active query, and external ID update operations. All UC-1..5 tests pass.",
          "test_file": "tests/unit/orchestrator/session-store.test.ts",
          "scenario_name": "UC-1, UC-2, UC-3, UC-4, UC-5"
        },
        {
          "id": "02-02",
          "name": "Replace in-memory registry with session store",
          "criteria": "Module-level session registry eliminated. Session lookup routes through SurrealDB via session store. HP-5 passes (status shows active).",
          "test_file": "tests/acceptance/sandbox-session-lifecycle.test.ts",
          "scenario_name": "HP-5"
        },
        {
          "id": "02-03",
          "name": "Wire adapter for spawn and prompt",
          "criteria": "Session creation delegates to adapter. Prompt delivery delegates to adapter instead of returning 409. HP-1 and HP-6 pass.",
          "test_file": "tests/acceptance/sandbox-session-lifecycle.test.ts",
          "scenario_name": "HP-1, HP-6"
        },
        {
          "id": "02-04",
          "name": "Route wiring and event bridge to SSE",
          "criteria": "Adapter injected via route wiring. Event bridge connected to SSE delivery. Old SDK event translation removed. HP-2 and HP-3 pass.",
          "test_file": "tests/acceptance/sandbox-session-lifecycle.test.ts",
          "scenario_name": "HP-2, HP-3"
        }
      ]
    },
    {
      "id": "03",
      "name": "Integration and Walking Skeleton",
      "steps": [
        {
          "id": "03-01",
          "name": "Walking skeleton E2E acceptance test",
          "criteria": "WS-1 passes: spawn, prompt, SSE events, SurrealDB record verified. Error paths EP-1, EP-2, EP-5 pass.",
          "test_file": "tests/acceptance/sandbox-session-lifecycle.test.ts",
          "scenario_name": "WS-1, EP-1, EP-2, EP-5"
        },
        {
          "id": "03-02",
          "name": "Multi-turn, persistence, remaining tests",
          "criteria": "WS-2, WS-3, HP-4 pass. Error paths EP-3, EP-4, EP-6, EP-7 pass. Edge cases EC-1, EC-2 pass.",
          "test_file": "tests/acceptance/sandbox-session-lifecycle.test.ts",
          "scenario_name": "WS-2, WS-3, HP-4, EP-3, EP-4, EP-6, EP-7, EC-1, EC-2"
        }
      ]
    },
    {
      "id": "04",
      "name": "R2: Proxy Token with Intent Binding + Adapter Env Wiring",
      "steps": [
        {
          "id": "04-01",
          "name": "Schema migration: add intent + session fields to proxy_token",
          "criteria": "Migration adds option<record<intent>> intent field and option<record<agent_session>> session field to proxy_token table. resolveProxyAuth returns intentId and sessionId when present. ProxyAuthResult type extended. Unit tests verify round-trip: token with intent+session resolves correctly. Token without intent (legacy CLI tokens) still resolves.",
          "test_file": "tests/unit/proxy/proxy-auth.test.ts",
          "scenario_name": "PA-10, PA-11, PA-12, PA-13"
        },
        {
          "id": "04-02",
          "name": "Extend SessionCreateRequest with env record",
          "criteria": "SessionCreateRequest type extended with optional env: Record<string, string>. Mock adapter captures env for assertion. createSessionViaAdapter passes env to adapter.createSession. Unit tests verify env passthrough and env omission when undefined.",
          "test_file": "tests/unit/orchestrator/sandbox-adapter.test.ts",
          "scenario_name": "UA-7, UA-8"
        },
        {
          "id": "04-03",
          "name": "Wire proxy token issuance into adapter spawn path",
          "criteria": "Adapter spawn path in routes.ts creates initial composite intent with BrainAction entries for expected tool chain (derived from task context). Runs intent through policy gate. Issues proxy token linked to authorized intent and session via new fields. Passes ANTHROPIC_BASE_URL (brainBaseUrl/proxy/llm/anthropic) and X-Brain-Auth (raw proxy token) as env to adapter. Acceptance test: proxy_token record has intent + session fields. Acceptance test: session env includes proxy URL + auth header.",
          "test_file": "tests/acceptance/sandbox-session-governance.test.ts",
          "scenario_name": "PW-1, PW-2, PW-3"
        }
      ]
    },
    {
      "id": "05",
      "name": "R2: Dynamic Per-Agent MCP Endpoint with Intent-Gated Tools",
      "steps": [
        {
          "id": "05-01",
          "name": "Agent MCP endpoint: tools/list with policy-derived gating hints",
          "criteria": "New route GET /mcp/agent/:sessionId/tools/list. Auth via X-Brain-Auth (resolveProxyAuth → identity + session). Returns all can_use granted tools. For each tool, checks if it is covered by any authorized intent linked to session via gates edges. Ungated tools (no intent required by policy): returned as-is. Gated tools (policy requires intent): description enriched with gating hint instructing agent to create an intent with goal+reasoning via create_intent before calling. Unit tests: ungated tool description unchanged, gated tool description includes intent instructions, invalid token 401.",
          "test_file": "tests/unit/mcp/agent-mcp-route.test.ts",
          "scenario_name": "AM-1, AM-2, AM-3, AM-4"
        },
        {
          "id": "05-02",
          "name": "Agent MCP endpoint: tools/call with intent check, 403 escalation, and trace",
          "criteria": "New route POST /mcp/agent/:sessionId/tools/call. Resolves session from proxy token. For the requested tool, checks if policy requires an intent. If no intent required: forward directly to upstream MCP. If intent required: queries all intents linked to session via gates edges, checks requested tool+params against union of authorization_details. If covered: forward to upstream MCP. If not covered: return 403 JSON-RPC error with structured body { code: -32403, message: 'intent_required', data: { tool, action_spec_template } } so agent knows to create an intent. All successful calls create trace record. Unit tests: ungated tool forwards without intent check, gated+covered tool succeeds, gated+uncovered tool returns intent_required 403, trace created on success.",
          "test_file": "tests/unit/mcp/agent-mcp-route.test.ts",
          "scenario_name": "AM-5, AM-6, AM-7, AM-8"
        },
        {
          "id": "05-03",
          "name": "Agent MCP endpoint: create_intent with yield-on-veto semantics",
          "criteria": "Agent MCP endpoint exposes create_intent tool (goal, reasoning, action_spec) alongside upstream MCP tools. create_intent runs the intent through policy gate. If auto-approved: creates gates edge to session, returns { status: 'authorized' } — agent proceeds to call the gated tool. If policy requires human review: creates intent in pending_veto, returns { status: 'pending_veto' } — agent must yield (stop working and let session go idle). Observer detects approved intent, re-invokes session via adapter.resumeSession. On resume, agent retries the tool call (now covered by the authorized intent). Unit tests: auto-approve returns authorized + gates edge, veto-required returns pending_veto without gates edge, resumed session can call previously gated tool after human approval + gates edge creation.",
          "test_file": "tests/unit/mcp/agent-mcp-route.test.ts",
          "scenario_name": "AM-9, AM-10, AM-11, AM-12"
        },
        {
          "id": "05-04",
          "name": "Wire MCP endpoint URL into session spawn env",
          "criteria": "After proxy token issued, add BRAIN_MCP_URL (brainBaseUrl/mcp/agent/{sessionId}) to adapter env alongside ANTHROPIC_BASE_URL. Same X-Brain-Auth token authenticates both planes. Unit test verifies env includes both URLs with matching token.",
          "test_file": "tests/unit/orchestrator/session-lifecycle.test.ts",
          "scenario_name": "SL-10, SL-11"
        }
      ]
    },
    {
      "id": "06",
      "name": "R2: Agent-Driven Escalation E2E",
      "steps": [
        {
          "id": "06-01",
          "name": "Acceptance test: agent-driven intent escalation flow",
          "criteria": "ESC-1: Spawn session with 2 tools granted (1 ungated, 1 gated). tools/list returns both; gated tool description includes intent instructions. ESC-2: tools/call on ungated tool succeeds immediately without intent. ESC-3: tools/call on gated tool without intent returns 403 intent_required with action_spec_template. ESC-4: Agent calls create_intent with goal+reasoning+action_spec, intent auto-approved, gates edge created. ESC-5: Retry tools/call on gated tool now succeeds, trace record created. ESC-6: tools/list now shows gated tool without hint (intent covers it).",
          "test_file": "tests/acceptance/sandbox-session-governance.test.ts",
          "scenario_name": "ESC-1, ESC-2, ESC-3, ESC-4, ESC-5, ESC-6"
        },
        {
          "id": "06-02",
          "name": "Acceptance test: yield-and-resume veto flow + E2E provenance",
          "criteria": "GOV-1: Spawn session, verify proxy URL + MCP URL in env. GOV-2: proxy_token has intent + session fields linking to initial intent. GOV-3: Agent calls create_intent for high-risk tool, policy routes to pending_veto, create_intent returns { status: 'pending_veto' }. GOV-4: Agent yields — session transitions to idle/suspended. GOV-5: Human approves via existing intent approve endpoint, gates edge created linking escalation intent to session. GOV-6: Observer detects authorized intent, re-invokes session via adapter.resumeSession. GOV-7: Resumed agent retries tools/call on gated tool, now succeeds. GOV-8: Full provenance chain: initial intent → gates → session, escalation intent → gates → session, proxy_token → initial intent, trace → tool call.",
          "test_file": "tests/acceptance/sandbox-session-governance.test.ts",
          "scenario_name": "GOV-1, GOV-2, GOV-3, GOV-4, GOV-5, GOV-6, GOV-7, GOV-8"
        }
      ]
    }
  ],
  "implementation_scope": {
    "source_directories": [
      "app/src/server/orchestrator/",
      "app/src/server/mcp/",
      "app/src/server/proxy/",
      "app/src/shared/",
      "schema/migrations/"
    ],
    "test_directories": [
      "tests/unit/orchestrator/",
      "tests/unit/mcp/",
      "tests/acceptance/"
    ],
    "excluded_patterns": [
      "node_modules/**",
      "dist/**",
      "*.d.ts"
    ]
  },
  "validation": {
    "status": "approved",
    "reviewer": "nw-solution-architect-reviewer",
    "approved_at": "2026-03-25T06:45:00Z"
  }
}

