 1→/**
 2→ * Tool Injector — Pure Function
 3→ *
 4→ * Merges Brain-managed tool definitions into the LLM request body's tools[].
 5→ * Runtime tools are preserved unmodified; Brain tools are appended after.
 6→ * When a name collision occurs, the runtime version takes precedence (Brain tool skipped).
 7→ *
 8→ * Step 7.5 in the proxy pipeline (between context injection and forwarding).
 9→ */
10→
11→// ---------------------------------------------------------------------------
12→// Types
13→// ---------------------------------------------------------------------------
14→
15→/** Anthropic tool format (the shape expected by the Messages API). */
16→export type AnthropicTool = {
17→  name: string;
18→  description: string;
19→  input_schema: Record<string, unknown>;
20→  output_schema?: Record<string, unknown>;
21→};
22→
23→/** Resolved tool from Brain's can_use graph query (internal, richer than Anthropic format). */
24→export type ResolvedTool = {
25→  name: string;
26→  description: string;
27→  input_schema: Record<string, unknown>;
28→  output_schema?: Record<string, unknown>;
29→  toolkit: string;
30→  risk_level: string;
31→  source_server_id?: string;
32→};
33→
34→// ---------------------------------------------------------------------------
35→// Pure Function: injectTools
36→// ---------------------------------------------------------------------------
37→
38→/**
39→ * Merge Brain-managed tools into the request's tool list.
40→ *
41→ * - Runtime tools are preserved first, unmodified.
42→ * - Brain tools are appended, but only if no runtime tool shares the same name.
43→ * - Output is in Anthropic tool format (name, description, input_schema only).
44→ *
45→ * @param runtimeTools - Tools already in the request body (may be undefined)
46→ * @param resolvedTools - Brain-managed tools resolved from can_use edges
47→ * @returns Merged tool list in Anthropic format
48→ */
49→export function injectTools(
50→  runtimeTools: AnthropicTool[] | undefined,
51→  resolvedTools: ResolvedTool[],
52→): AnthropicTool[] {
53→  const existing = runtimeTools ?? [];
54→
55→  if (resolvedTools.length === 0) {
56→    return [...existing];
57→  }
58→
59→  const runtimeNames = new Set(existing.map((tool) => tool.name));
60→
61→  const brainToolsToInject: AnthropicTool[] = resolvedTools
62→    .filter((tool) => !runtimeNames.has(tool.name))
63→    .map(toAnthropicFormat);
64→
65→  return [...existing, ...brainToolsToInject];
66→}
67→
68→// ---------------------------------------------------------------------------
69→// Internal: Format Conversion
70→// ---------------------------------------------------------------------------
71→
72→/** Strip internal fields (toolkit, risk_level) to produce Anthropic-compatible tool. */
73→function toAnthropicFormat(tool: ResolvedTool): AnthropicTool {
74→  const result: AnthropicTool = {
75→    name: tool.name,
76→    description: tool.description,
77→    input_schema: tool.input_schema,
78→  };
79→  if (tool.output_schema) {
80→    result.output_schema = tool.output_schema;
81→  }
82→  return result;
83→}
84→

  1→/**
  2→ * Tool Resolver — Identity Toolset Resolution
  3→ *
  4→ * Resolves an identity's effective toolset by querying can_use edges in the graph.
  5→ * Uses a per-instance Map-based cache with configurable TTL (not a module-level singleton).
  6→ *
  7→ * Port signature (injectable query):
  8→ *   QueryGrantedTools = (identityId, workspaceId) => Promise<ResolvedTool[]>
  9→ *
 10→ * The query function is injected as a dependency, keeping the resolver pure
 11→ * (aside from the cache, which is an explicit parameter).
 12→ */
 13→import { RecordId, type Surreal } from "surrealdb";
 14→
 15→// ---------------------------------------------------------------------------
 16→// Types
 17→// ---------------------------------------------------------------------------
 18→
 19→export type { ResolvedTool } from "./tool-injector";
 20→
 21→/** Resolved tool from can_use graph query. Re-exported from tool-injector. */
 22→import type { ResolvedTool } from "./tool-injector";
 23→
 24→/** Port: query function for fetching granted tools from the graph. */
 25→export type QueryGrantedTools = (
 26→  identityId: string,
 27→  workspaceId: string,
 28→) => Promise<ResolvedTool[]>;
 29→
 30→/** Cache entry with TTL tracking. */
 31→type CacheEntry = {
 32→  tools: ResolvedTool[];
 33→  populatedAt: number;
 34→};
 35→
 36→/** Per-instance cache (Map-based, injected via deps). */
 37→export type ToolResolutionCache = {
 38→  readonly cache: Map<string, CacheEntry>;
 39→  readonly ttlMs: number;
 40→};
 41→
 42→// ---------------------------------------------------------------------------
 43→// Cache Factory
 44→// ---------------------------------------------------------------------------
 45→
 46→const DEFAULT_TTL_MS = 60_000; // 60 seconds
 47→
 48→/**
 49→ * Create a new tool resolution cache instance.
 50→ * Each call returns a fresh Map — no module-level singletons.
 51→ */
 52→export function createToolResolutionCache(
 53→  ttlMs: number = DEFAULT_TTL_MS,
 54→): ToolResolutionCache {
 55→  return {
 56→    cache: new Map(),
 57→    ttlMs,
 58→  };
 59→}
 60→
 61→// ---------------------------------------------------------------------------
 62→// Resolver (pure core with injectable query)
 63→// ---------------------------------------------------------------------------
 64→
 65→/**
 66→ * Resolve the effective toolset for an identity within a workspace.
 67→ *
 68→ * - Checks cache first (composite key: identityId + workspaceId)
 69→ * - If cache miss or expired, calls the query function and caches the result
 70→ * - Returns ResolvedTool[] (may be empty for identities with no grants)
 71→ */
 72→export async function resolveToolsForIdentity(
 73→  identityId: string,
 74→  workspaceId: string,
 75→  queryGrantedTools: QueryGrantedTools,
 76→  cache: ToolResolutionCache,
 77→): Promise<ResolvedTool[]> {
 78→  const cacheKey = `${identityId}:${workspaceId}`;
 79→  const now = Date.now();
 80→
 81→  const cached = cache.cache.get(cacheKey);
 82→  if (cached && now - cached.populatedAt < cache.ttlMs) {
 83→    return cached.tools;
 84→  }
 85→
 86→  const tools = await queryGrantedTools(identityId, workspaceId);
 87→  cache.cache.set(cacheKey, { tools, populatedAt: now });
 88→
 89→  return tools;
 90→}
 91→
 92→// ---------------------------------------------------------------------------
 93→// Adapter: SurrealDB Query Function Factory
 94→// ---------------------------------------------------------------------------
 95→
 96→/**
 97→ * Create a QueryGrantedTools function backed by SurrealDB.
 98→ * Queries can_use edges to find active tools granted to the identity.
 99→ */
100→export function createQueryGrantedTools(surreal: Surreal): QueryGrantedTools {
101→  return async (identityId: string, workspaceId: string): Promise<ResolvedTool[]> => {
102→    const identityRecord = new RecordId("identity", identityId);
103→    const workspaceRecord = new RecordId("workspace", workspaceId);
104→
105→    type ToolRow = {
106→      name: string;
107→      description: string;
108→      input_schema: Record<string, unknown>;
109→      output_schema?: Record<string, unknown>;
110→      toolkit: string;
111→      risk_level: string;
112→      source_server_id?: string;
113→    };
114→
115→    const results = await surreal.query<[ToolRow[]]>(
116→      `SELECT out.name AS name, out.description AS description, out.input_schema AS input_schema, out.output_schema AS output_schema, out.toolkit AS toolkit, out.risk_level AS risk_level, out.source_server.id AS source_server_id
117→       FROM can_use
118→       WHERE in = $identity AND out.status = 'active' AND out.workspace = $workspace;`,
119→      { identity: identityRecord, workspace: workspaceRecord },
120→    );
121→
122→    return (results[0] ?? []).map((row) => ({
123→      name: row.name,
124→      description: row.description,
125→      input_schema: row.input_schema,
126→      output_schema: row.output_schema,
127→      toolkit: row.toolkit,
128→      risk_level: row.risk_level,
129→      source_server_id: row.source_server_id,
130→    }));
131→  };
132→}
