  1→/**
  2→ * Proxy Auth Middleware — Resolve Brain auth tokens to workspace + identity
  3→ *
  4→ * Pipeline:
  5→ *   1. Extract X-Brain-Auth header value
  6→ *   2. SHA-256 hash the raw token
  7→ *   3. Check in-memory TTL cache for cached resolution
  8→ *   4. If cache miss, query proxy_token table for valid (non-expired, non-revoked) record
  9→ *   5. Cache the resolution result
 10→ *   6. Return { workspaceId, identityId } or undefined (pass-through)
 11→ *
 12→ * Driving port: extractBrainAuthToken, resolveProxyAuth
 13→ * Driven port: LookupProxyToken (function signature — SurrealDB adapter)
 14→ *
 15→ * Design:
 16→ *   - Pure core functions (extractBrainAuthToken, resolveProxyAuth logic)
 17→ *   - Cache injected as dependency (no module-level singletons)
 18→ *   - LookupProxyToken is a function signature (port), not a concrete DB call
 19→ */
 20→import { RecordId } from "surrealdb";
 21→import { hashProxyToken } from "./proxy-token-core";
 22→import type { ServerDependencies } from "../runtime/types";
 23→
 24→// ---------------------------------------------------------------------------
 25→// Types
 26→// ---------------------------------------------------------------------------
 27→
 28→export type ProxyAuthResult = {
 29→  workspaceId: string;
 30→  identityId: string;
 31→  intentId?: string;
 32→  sessionId?: string;
 33→};
 34→
 35→export type ProxyTokenRecord = {
 36→  workspaceId: string;
 37→  identityId: string;
 38→  expiresAt: Date;
 39→  revoked: boolean;
 40→  intentId?: string;
 41→  sessionId?: string;
 42→};
 43→
 44→/** Driven port: look up a proxy token by its SHA-256 hash */
 45→export type LookupProxyToken = (
 46→  tokenHash: string,
 47→) => Promise<ProxyTokenRecord | undefined>;
 48→
 49→export type TokenCacheEntry = {
 50→  result: ProxyAuthResult;
 51→  expiresAt: number; // epoch ms
 52→};
 53→
 54→export type TokenCache = Map<string, TokenCacheEntry>;
 55→
 56→// ---------------------------------------------------------------------------
 57→// Pure Functions
 58→// ---------------------------------------------------------------------------
 59→
 60→/**
 61→ * Extract the Brain auth token from request headers.
 62→ * Returns undefined if the header is missing or empty (pass-through to existing auth).
 63→ */
 64→export function extractBrainAuthToken(
 65→  headers: Headers,
 66→): string | undefined {
 67→  const value = headers.get("X-Brain-Auth");
 68→  if (!value || value.trim().length === 0) return undefined;
 69→  return value.trim();
 70→}
 71→
 72→/**
 73→ * Create a TTL-based token cache. Returns a plain Map — the TTL is enforced
 74→ * at read time by resolveProxyAuth, not by the cache itself.
 75→ */
 76→export function createTokenCache(): TokenCache {
 77→  return new Map();
 78→}
 79→
 80→/**
 81→ * Check the cache for a valid (non-expired) entry.
 82→ * Returns the cached ProxyAuthResult or undefined if miss/expired.
 83→ */
 84→export function getCachedAuth(
 85→  cache: TokenCache,
 86→  tokenHash: string,
 87→  nowMs: number,
 88→): ProxyAuthResult | undefined {
 89→  const entry = cache.get(tokenHash);
 90→  if (!entry) return undefined;
 91→  if (nowMs >= entry.expiresAt) {
 92→    cache.delete(tokenHash);
 93→    return undefined;
 94→  }
 95→  return entry.result;
 96→}
 97→
 98→/**
 99→ * Store a resolution result in the cache with a TTL.
100→ */
101→export function setCachedAuth(
102→  cache: TokenCache,
103→  tokenHash: string,
104→  result: ProxyAuthResult,
105→  ttlMs: number,
106→  nowMs: number,
107→): void {
108→  cache.set(tokenHash, {
109→    result,
110→    expiresAt: nowMs + ttlMs,
111→  });
112→}
113→
114→// ---------------------------------------------------------------------------
115→// Orchestrator (still pure — IO injected via LookupProxyToken)
116→// ---------------------------------------------------------------------------
117→
118→const DEFAULT_CACHE_TTL_MS = 5 * 60 * 1000; // 5 minutes
119→
120→export type ResolveProxyAuthOptions = {
121→  cacheTtlMs?: number;
122→  now?: () => number;
123→};
124→
125→/**
126→ * Resolve a Brain auth token to workspace + identity.
127→ *
128→ * Returns:
129→ *   - ProxyAuthResult on success (valid, non-expired, non-revoked token)
130→ *   - undefined when no X-Brain-Auth header is present (pass-through)
131→ *   - Throws with descriptive message for invalid/expired/revoked tokens
132→ *
133→ * @param headers - Request headers
134→ * @param lookupToken - Driven port for DB lookup
135→ * @param cache - Injected token cache
136→ * @param options - Optional TTL and clock overrides
137→ */
138→export async function resolveProxyAuth(
139→  headers: Headers,
140→  lookupToken: LookupProxyToken,
141→  cache: TokenCache,
142→  options?: ResolveProxyAuthOptions,
143→): Promise<ProxyAuthResult | undefined> {
144→  const rawToken = extractBrainAuthToken(headers);
145→  if (!rawToken) return undefined;
146→
147→  const tokenHash = hashProxyToken(rawToken);
148→  const nowMs = (options?.now ?? Date.now)();
149→  const cacheTtlMs = options?.cacheTtlMs ?? DEFAULT_CACHE_TTL_MS;
150→
151→  // Check cache first
152→  const cached = getCachedAuth(cache, tokenHash, nowMs);
153→  if (cached) return cached;
154→
155→  // DB lookup via driven port
156→  const record = await lookupToken(tokenHash);
157→
158→  if (!record) {
159→    throw new ProxyAuthError("invalid_token", "Proxy token not found or expired");
160→  }
161→
162→  if (record.revoked) {
163→    throw new ProxyAuthError("token_revoked", "Proxy token has been revoked");
164→  }
165→
166→  if (record.expiresAt.getTime() <= nowMs) {
167→    throw new ProxyAuthError("token_expired", "Proxy token has expired");
168→  }
169→
170→  const result: ProxyAuthResult = {
171→    workspaceId: record.workspaceId,
172→    identityId: record.identityId,
173→    ...(record.intentId ? { intentId: record.intentId } : {}),
174→    ...(record.sessionId ? { sessionId: record.sessionId } : {}),
175→  };
176→
177→  // Cache the successful resolution — cap TTL at token's remaining validity
178→  // so the cache never outlasts the authoritative DB expiry
179→  const remainingMs = record.expiresAt.getTime() - nowMs;
180→  setCachedAuth(cache, tokenHash, result, Math.min(cacheTtlMs, remainingMs), nowMs);
181→
182→  return result;
183→}
184→
185→// ---------------------------------------------------------------------------
186→// SurrealDB Adapter (driven port implementation)
187→// ---------------------------------------------------------------------------
188→
189→type ProxyTokenRow = {
190→  workspace: RecordId;
191→  identity: RecordId;
192→  expires_at: Date;
193→  revoked: boolean;
194→  intent?: RecordId;
195→  session?: RecordId;
196→};
197→
198→/**
199→ * Create a LookupProxyToken adapter backed by SurrealDB.
200→ * Queries the proxy_token table for a non-revoked, non-expired record
201→ * matching the given token hash.
202→ */
203→export function createLookupProxyToken(
204→  surreal: ServerDependencies["surreal"],
205→): LookupProxyToken {
206→  return async (tokenHash: string): Promise<ProxyTokenRecord | undefined> => {
207→    const results = await surreal.query<[ProxyTokenRow[]]>(
208→      `SELECT workspace, identity, expires_at, revoked, intent, session FROM proxy_token WHERE token_hash = $hash LIMIT 1;`,
209→      { hash: tokenHash },
210→    );
211→
212→    const row = results[0]?.[0];
213→    if (!row) return undefined;
214→
215→    return {
216→      workspaceId: row.workspace.id as string,
217→      identityId: row.identity.id as string,
218→      expiresAt: new Date(row.expires_at),
219→      revoked: row.revoked,
220→      ...(row.intent ? { intentId: row.intent.id as string } : {}),
221→      ...(row.session ? { sessionId: row.session.id as string } : {}),
222→    };
223→  };
224→}
225→
226→// ---------------------------------------------------------------------------
227→// Error Type
228→// ---------------------------------------------------------------------------
229→
230→export type ProxyAuthErrorCode = "invalid_token" | "token_revoked" | "token_expired";
231→
232→export class ProxyAuthError extends Error {
233→  readonly code: ProxyAuthErrorCode;
234→
235→  constructor(code: ProxyAuthErrorCode, message: string) {
236→    super(message);
237→    this.name = "ProxyAuthError";
238→    this.code = code;
239→  }
240→}
