 1→/**
 2→ * RAR Operation Scope Verifier
 3→ *
 4→ * Matches a requested BrainAction against an array of authorized
 5→ * BrainActions from a token's authorization_details claim.
 6→ *
 7→ * Pure function. No IO imports.
 8→ */
 9→import type { BrainAction, RARVerificationResult } from "./types";
10→
11→function findMatchingAuthorization(
12→  requested: BrainAction,
13→  authorized: BrainAction[],
14→): BrainAction | undefined {
15→  return authorized.find(
16→    (auth) =>
17→      auth.type === requested.type &&
18→      auth.action === requested.action &&
19→      auth.resource === requested.resource,
20→  );
21→}
22→
23→export function findExceededConstraint(
24→  requestedConstraints: Record<string, unknown>,
25→  authorizedConstraints: Record<string, unknown>,
26→): string | undefined {
27→  return Object.keys(requestedConstraints).find((key) => {
28→    const requestedValue = requestedConstraints[key];
29→    const authorizedValue = authorizedConstraints[key];
30→
31→    // Numeric bounds: requested must not exceed authorized
32→    if (typeof requestedValue === "number" && typeof authorizedValue === "number") {
33→      return requestedValue > authorizedValue;
34→    }
35→
36→    // String identity: requested must exactly match authorized
37→    if (typeof requestedValue === "string" && typeof authorizedValue === "string") {
38→      return requestedValue !== authorizedValue;
39→    }
40→
41→    // If authorized has a constraint but requested has a different type, treat as exceeded
42→    if (authorizedValue !== undefined && typeof requestedValue !== typeof authorizedValue) {
43→      return true;
44→    }
45→
46→    return false;
47→  });
48→}
49→
50→export function verifyOperationScope(
51→  requested: BrainAction,
52→  authorized: BrainAction[],
53→): RARVerificationResult {
54→  const match = findMatchingAuthorization(requested, authorized);
55→
56→  if (!match) {
57→    return {
58→      authorized: false,
59→      error: `No authorization for ${requested.action} on ${requested.resource}`,
60→      code: "authorization_details_mismatch",
61→    };
62→  }
63→
64→  if (requested.constraints && match.constraints) {
65→    const exceeded = findExceededConstraint(requested.constraints, match.constraints);
66→    if (exceeded) {
67→      const requestedValue = requested.constraints[exceeded];
68→      const authorizedValue = match.constraints[exceeded];
69→      return {
70→        authorized: false,
71→        error: `Constraint ${exceeded} value ${requestedValue} exceeds authorized bound ${authorizedValue}`,
72→        code: "authorization_params_exceeded",
73→      };
74→    }
75→  }
76→
77→  return { authorized: true };
78→}
