  1→/**
  2→ * Sandbox Agent Adapter -- port types and adapter factories.
  3→ *
  4→ * Port types define the contract for interacting with a SandboxAgent server.
  5→ * The adapter abstracts at the SDK level: one factory wraps the real SDK instance,
  6→ * another provides a test-injectable mock with overridable behavior.
  7→ *
  8→ * Real SDK types are re-exported for use by callers without direct SDK dependency.
  9→ */
 10→import type {
 11→  SandboxAgent,
 12→  Session,
 13→  SessionCreateRequest,
 14→  SessionEvent,
 15→  SessionEventListener,
 16→  SessionPermissionRequest,
 17→  PermissionRequestListener,
 18→  PermissionReply,
 19→  PromptRequest,
 20→  PromptResponse,
 21→} from "sandbox-agent";
 22→
 23→// Re-export SDK types used at port boundaries
 24→export type {
 25→  SessionEvent,
 26→  SessionEventListener,
 27→  SessionPermissionRequest,
 28→  PermissionRequestListener,
 29→  PermissionReply,
 30→  PromptResponse,
 31→};
 32→
 33→// ── Port Types ──
 34→
 35→/**
 36→ * Brain-owned session creation request.
 37→ * Extends the SDK's SessionCreateRequest with env for passing environment
 38→ * variables (e.g. ANTHROPIC_BASE_URL, X-Brain-Auth) into the sandbox.
 39→ */
 40→export type CreateSessionRequest = SessionCreateRequest & {
 41→  env?: Record<string, string>;
 42→};
 43→
 44→/**
 45→ * Thin wrapper around the SDK's Session, exposing only the methods Brain needs.
 46→ * Keeps the port boundary narrow -- callers never depend on the full Session class.
 47→ */
 48→export type SessionHandle = {
 49→  id: string;
 50→  prompt: (
 51→    messages: PromptRequest["prompt"],
 52→  ) => Promise<PromptResponse>;
 53→  onEvent: (listener: SessionEventListener) => () => void;
 54→  onPermissionRequest: (listener: PermissionRequestListener) => () => void;
 55→  respondPermission: (permissionId: string, reply: PermissionReply) => Promise<void>;
 56→};
 57→
 58→export type SandboxAgentAdapter = {
 59→  createSession: (request: CreateSessionRequest) => Promise<SessionHandle>;
 60→  resumeSession: (sessionId: string) => Promise<SessionHandle>;
 61→  destroySession: (sessionId: string) => Promise<void>;
 62→  /** Exposed for test assertion -- last request passed to createSession. */
 63→  lastCreateSessionRequest?: CreateSessionRequest;
 64→};
 65→
 66→// ── Production Adapter Factory ──
 67→
 68→function wrapSession(session: Session): SessionHandle {
 69→  return {
 70→    id: session.id,
 71→    prompt: (messages) => session.prompt(messages),
 72→    onEvent: (listener) => session.onEvent(listener),
 73→    onPermissionRequest: (listener) => session.onPermissionRequest(listener),
 74→    respondPermission: (permissionId, reply) => session.respondPermission(permissionId, reply),
 75→  };
 76→}
 77→
 78→/**
 79→ * Creates a production adapter backed by a real SandboxAgent SDK instance.
 80→ * The SDK instance should be created via `SandboxAgent.start()` or `SandboxAgent.connect()`.
 81→ */
 82→export function createSandboxAgentAdapter(
 83→  sdk: SandboxAgent,
 84→): SandboxAgentAdapter {
 85→  return {
 86→    createSession: async (request) => {
 87→      // Extract env from Brain's extended request; pass the SDK-compatible fields through
 88→      const { env: _env, ...sdkRequest } = request;
 89→      const session = await sdk.createSession(sdkRequest);
 90→      return wrapSession(session);
 91→    },
 92→    resumeSession: async (sessionId) => {
 93→      const session = await sdk.resumeSession(sessionId);
 94→      return wrapSession(session);
 95→    },
 96→    destroySession: async (sessionId) => {
 97→      await sdk.destroySession(sessionId);
 98→    },
 99→  };
100→}
101→
102→// ── Mock Adapter Factory ──
103→
104→export function createMockAdapter(
105→  overrides?: Partial<SandboxAgentAdapter>,
106→): SandboxAgentAdapter {
107→  const sessions = new Map<string, SessionHandle>();
108→  const destroyed = new Set<string>();
109→  let lastCreateSessionRequest: CreateSessionRequest | undefined;
110→
111→  const createHandle = (id: string): SessionHandle => ({
112→    id,
113→    prompt: async () => {
114→      if (destroyed.has(id)) {
115→        throw new Error(`Session ${id} has been destroyed`);
116→      }
117→      return { stopReason: "end_turn" as const } as PromptResponse;
118→    },
119→    onEvent: () => () => {},
120→    onPermissionRequest: () => () => {},
121→    respondPermission: async () => {
122→      if (destroyed.has(id)) {
123→        throw new Error(`Session ${id} has been destroyed`);
124→      }
125→    },
126→  });
127→
128→  return {
129→    get lastCreateSessionRequest() {
130→      return lastCreateSessionRequest;
131→    },
132→    createSession: async (request) => {
133→      lastCreateSessionRequest = request;
134→      const id = `session-${crypto.randomUUID()}`;
135→      const handle = createHandle(id);
136→      sessions.set(id, handle);
137→      return handle;
138→    },
139→    resumeSession: async (sessionId) => {
140→      if (destroyed.has(sessionId)) {
141→        throw new Error(`Session ${sessionId} has been destroyed`);
142→      }
143→      const existing = sessions.get(sessionId);
144→      if (existing) {
145→        return existing;
146→      }
147→      const handle = createHandle(sessionId);
148→      sessions.set(sessionId, handle);
149→      return handle;
150→    },
151→    destroySession: async (sessionId) => {
152→      sessions.delete(sessionId);
153→      destroyed.add(sessionId);
154→    },
155→    ...overrides,
156→  };
157→}
158→

