 94→// ---------------------------------------------------------------------------
 95→// Event iteration — port (dependencies as function signatures)
 96→// ---------------------------------------------------------------------------
 97→
 98→export type EventIterationDeps = {
 99→  emitEvent: (streamId: string, event: StreamEvent) => void;
100→  updateSessionStatus: (
101→    sessionId: string,
102→    status: OrchestratorStatus,
103→    error?: string,
104→  ) => Promise<void>;
105→  updateLastEventAt: (sessionId: string) => Promise<void>;
106→  getSessionStatus: (sessionId: string) => Promise<OrchestratorStatus>;
107→  startStallDetector: (sessionId: string, streamId: string) => StallDetectorHandle;
108→};
109→
110→const TERMINAL_STATUSES: ReadonlySet<string> = new Set<string>(
111→  TERMINAL_ORCHESTRATOR_STATUSES,
112→);
113→
114→/**
115→ * Iterates the SDK message stream, forwarding messages through the event
116→ * bridge. Transitions session to "active" on first message, starts stall
117→ * detection, and stops on terminal status or error.
118→ *
119→ * Returns a Promise that resolves when iteration ends (for testing).
120→ * In production, this is launched fire-and-forget.
121→ */
122→export function startEventIteration(
123→  deps: EventIterationDeps,
124→  messageStream: AsyncIterable<unknown>,
125→  streamId: string,
126→  sessionId: string,
127→): Promise<void> {
128→  const stallDetector = deps.startStallDetector(sessionId, streamId);
129→
130→  const bridge = startEventBridge(
131→    {
132→      emitEvent: deps.emitEvent,
133→      updateLastEventAt: deps.updateLastEventAt,
134→    },
135→    streamId,
136→    sessionId,
137→    stallDetector,
138→  );
139→
140→  let firstMessageReceived = false;
141→  let messageCount = 0;
142→
143→  async function iterate(): Promise<void> {
144→    log.info("orchestrator.iteration", "Event iteration started, awaiting SDK messages", { sessionId, streamId });
145→    try {
146→      for await (const rawMessage of messageStream) {
147→        messageCount++;
148→        const msg = rawMessage as SdkMessage;
149→        log.info("orchestrator.iteration", `SDK message received (#${messageCount})`, {
150→          sessionId,
151→          messageType: msg.type,
152→          ...(msg.type === "result" ? { subtype: msg.subtype, ...(msg.subtype === "error" ? { error: msg.error } : {}) } : {}),
153→          ...(msg.type === "system" ? { subtype: msg.subtype } : {}),
154→        });
155→
156→        // Check if session has reached terminal status
157→        const currentStatus = await deps.getSessionStatus(sessionId);
158→        if (TERMINAL_STATUSES.has(currentStatus)) {
159→          log.info("orchestrator.iteration", "Stopping: session reached terminal status", { sessionId, currentStatus });
160→          break;
161→        }
162→
163→        // Transition to active on first message
164→        if (!firstMessageReceived) {
165→          firstMessageReceived = true;
166→          await deps.updateSessionStatus(sessionId, "active");
167→        }
168→
169→        // Forward through event bridge (transform + emit + stall detection)
170→        bridge.handleMessage(msg);
171→      }
172→      log.info("orchestrator.iteration", "Event iteration ended normally", { sessionId, messageCount });
173→      // Transition to idle when stream ends normally and agent produced output
174→      if (firstMessageReceived) {
175→        const finalStatus = await deps.getSessionStatus(sessionId);
176→        if (!TERMINAL_STATUSES.has(finalStatus)) {
177→          await deps.updateSessionStatus(sessionId, "idle");
178→        }
179→      }
180→    } catch (err) {
181→      const errorMessage = err instanceof Error ? err.message : String(err);
182→      log.error("orchestrator.iteration", "Agent message stream error", err, { sessionId, streamId });
183→      await deps.updateSessionStatus(sessionId, "error", errorMessage);
184→    } finally {
185→      if (!firstMessageReceived) {
186→        log.warn("orchestrator.iteration", "Agent stream ended with zero messages", { sessionId, streamId });
187→      }
188→      bridge.stop();
189→    }
190→  }
191→
192→  return iterate();
193→}
