199→export function pickDefined<T extends Record<string, unknown>>(obj: T): Partial<T> {
200→  const result: Record<string, unknown> = {};
201→  for (const [key, value] of Object.entries(obj)) {
202→    if (value !== undefined) {
203→      result[key] = value;
204→    }
205→  }
206→  return result as Partial<T>;
207→}
