251→type SessionLookup =
252→  | { ok: true; session: SessionRow; record: RecordId<"agent_session", string>; status: OrchestratorStatus }
253→  | { ok: false; error: SessionError };
254→
255→async function lookupSession(
256→  surreal: Surreal,
257→  sessionId: string,
258→): Promise<SessionLookup> {
259→  const record = new RecordId("agent_session", sessionId);
260→  const session = await surreal.select<SessionRow>(record);
261→  if (!session) {
262→    return { ok: false, error: sessionNotFound(sessionId) };
263→  }
264→  if (!session.orchestrator_status) {
265→    throw new Error(`agent_session ${sessionId} missing orchestrator_status — data corruption`);
266→  }
267→  const status = session.orchestrator_status as OrchestratorStatus;
268→  return { ok: true, session, record, status };
269→}
270→
271→function requireWorkspace(session: SessionRow, sessionId: string): RecordId<"workspace", string> {
272→  if (!session.workspace) {
273→    throw new Error(`agent_session ${sessionId} missing workspace — data corruption`);
274→  }
275→  return session.workspace as RecordId<"workspace", string>;
276→}
