530→// ---------------------------------------------------------------------------
531→// abortOrchestratorSession
532→// ---------------------------------------------------------------------------
533→
534→type AbortSessionInput = {
535→  surreal: Surreal;
536→  shellExec: ShellExec;
537→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
538→  sessionId: string;
539→  adapter: SandboxAgentAdapter;
540→  endAgentSession: (input: {
541→    surreal: Surreal;
542→    workspaceRecord: RecordId<"workspace", string>;
543→    sessionId: string;
544→    summary: string;
545→  }) => Promise<{ session_id: string; ended: boolean }>;
546→};
547→
548→export async function abortOrchestratorSession(
549→  input: AbortSessionInput,
550→): Promise<AbortSessionResult> {
551→  const lookup = await lookupSession(input.surreal, input.sessionId);
552→  if (!lookup.ok) {
553→    return { ok: false, error: lookup.error };
554→  }
555→  const { session, record: sessionRecord } = lookup;
556→
557→  // 1. Destroy the sandbox agent session
558→  if (session.external_session_id) {
559→    try {
560→      await input.adapter.destroySession(session.external_session_id);
561→    } catch (err) {
562→      log.warn("orchestrator.abort", "Failed to destroy sandbox session", {
563→        sessionId: input.sessionId,
564→        externalSessionId: session.external_session_id,
565→        error: String(err),
566→      });
567→    }
568→  }
569→
570→  // 2. Update orchestrator_status to aborted
571→  await input.surreal.update(sessionRecord).merge({
572→    orchestrator_status: "aborted" as OrchestratorStatus,
573→  });
574→
575→  const workspaceRecord = requireWorkspace(session, input.sessionId);
576→
577→  // 3. Remove worktree if branch name exists
578→  if (session.worktree_branch) {
579→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
580→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
581→  }
582→
583→  // 4. Return task to ready
584→  if (session.task_id) {
585→    await input.surreal.update(session.task_id).merge({
586→      status: "ready",
587→      updated_at: new Date(),
588→    });
589→  }
590→
591→  // 5. End the agent session
592→  await input.endAgentSession({
593→    surreal: input.surreal,
594→    workspaceRecord,
595→    sessionId: input.sessionId,
596→    summary: "Session aborted",
597→  });
598→
599→  return {
600→    ok: true,
601→    value: {
602→      aborted: true,
603→      sessionId: input.sessionId,
604→    },
605→  };
606→}
