608→// ---------------------------------------------------------------------------
609→// acceptOrchestratorSession
610→// ---------------------------------------------------------------------------
611→
612→type AcceptSessionInput = {
613→  surreal: Surreal;
614→  shellExec: ShellExec;
615→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
616→  sessionId: string;
617→  summary: string;
618→  adapter: SandboxAgentAdapter;
619→  endAgentSession: (input: {
620→    surreal: Surreal;
621→    workspaceRecord: RecordId<"workspace", string>;
622→    sessionId: string;
623→    summary: string;
624→  }) => Promise<{ session_id: string; ended: boolean }>;
625→};
626→
627→export async function acceptOrchestratorSession(
628→  input: AcceptSessionInput,
629→): Promise<AcceptSessionResult> {
630→  const lookup = await lookupSession(input.surreal, input.sessionId);
631→  if (!lookup.ok) {
632→    return { ok: false, error: lookup.error };
633→  }
634→  const { session, record: sessionRecord, status } = lookup;
635→
636→  if (!ACCEPTABLE_STATUSES.has(status)) {
637→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "accept") };
638→  }
639→
640→  const workspaceRecord = requireWorkspace(session, input.sessionId);
641→
642→  // 1. Destroy the sandbox agent session
643→  if (session.external_session_id) {
644→    try {
645→      await input.adapter.destroySession(session.external_session_id);
646→    } catch (err) {
647→      log.warn("orchestrator.accept", "Failed to destroy sandbox session", {
648→        sessionId: input.sessionId,
649→        externalSessionId: session.external_session_id,
650→        error: String(err),
651→      });
652→    }
653→  }
654→
655→  // 2. Update orchestrator_status to completed
656→  await input.surreal.update(sessionRecord).merge({
657→    orchestrator_status: "completed" as OrchestratorStatus,
658→  });
659→
660→  // 3. Remove worktree (branch is preserved for merge/review)
661→  if (session.worktree_branch) {
662→    const repoRoot = await input.resolveRepoRoot(workspaceRecord);
663→    await removeWorktree(input.shellExec, repoRoot, session.worktree_branch);
664→  }
665→
666→  // 4. End the agent session
667→  await input.endAgentSession({
668→    surreal: input.surreal,
669→    workspaceRecord,
670→    sessionId: input.sessionId,
671→    summary: input.summary,
672→  });
673→
674→  return {
675→    ok: true,
676→    value: {
677→      accepted: true,
678→      sessionId: input.sessionId,
679→    },
680→  };
681→}
