683→// ---------------------------------------------------------------------------
684→// State guard helpers
685→// ---------------------------------------------------------------------------
686→
687→const REVIEWABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
688→const REJECTABLE_STATUSES = new Set<OrchestratorStatus>(["idle"]);
689→const ACCEPTABLE_STATUSES = new Set<OrchestratorStatus>(["idle", "completed"]);
690→const PROMPTABLE_STATUSES = new Set<OrchestratorStatus>(["spawning", "active", "idle"]);
691→
692→function sessionStateConflict(sessionId: string, currentStatus: string, action: string): SessionError {
693→  return {
694→    code: "SESSION_ERROR",
695→    message: `Cannot ${action} session ${sessionId}: current status is ${currentStatus}`,
696→    httpStatus: 409,
697→  };
698→}
699→
700→function sessionAborted(sessionId: string): SessionError {
701→  return {
702→    code: "SESSION_ERROR",
703→    message: `Session ${sessionId} has been aborted`,
704→    httpStatus: 409,
705→  };
706→}
707→
708→// ---------------------------------------------------------------------------
709→// getOrchestratorReview
710→// ---------------------------------------------------------------------------
711→
712→type GetReviewInput = {
713→  surreal: Surreal;
714→  sessionId: string;
715→  getDiff: (repoRoot: string, branchName: string) => Promise<import("./worktree-manager").WorktreeResult<import("./worktree-manager").DiffResult>>;
716→  resolveRepoRoot: (workspaceRecord: RecordId<"workspace", string>) => Promise<string>;
717→  getTaskTitle: (taskId: string) => Promise<string>;
718→};
719→
720→export async function getOrchestratorReview(
721→  input: GetReviewInput,
722→): Promise<ReviewResult> {
723→  const lookup = await lookupSession(input.surreal, input.sessionId);
724→  if (!lookup.ok) {
725→    return { ok: false, error: lookup.error };
726→  }
727→  const { session, status } = lookup;
728→
729→  if (status === "aborted") {
730→    return { ok: false, error: sessionAborted(input.sessionId) };
731→  }
732→
733→  if (!REVIEWABLE_STATUSES.has(status)) {
734→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "review") };
735→  }
736→
737→  // Get diff from the branch
738→  const branchName = session.worktree_branch ?? "";
739→  const workspaceRecord = requireWorkspace(session, input.sessionId);
740→  const repoRoot = await input.resolveRepoRoot(workspaceRecord);
741→  const diffResult = await input.getDiff(repoRoot, branchName);
742→
743→  const diff = diffResult.ok
744→    ? diffResult.value
745→    : { files: [], rawDiff: "", stats: { filesChanged: 0, insertions: 0, deletions: 0 } };
746→
747→  // Get task title
748→  const taskId = session.task_id ? session.task_id.id : "";
749→  const taskTitle = taskId ? await input.getTaskTitle(taskId) : "";
750→
751→  return {
752→    ok: true,
753→    value: {
754→      taskTitle,
755→      diff,
756→      session: {
757→        orchestratorStatus: status,
758→        ...pickDefined({
759→          worktreeBranch: session.worktree_branch,
760→          startedAt: session.started_at,
761→          lastEventAt: session.last_event_at,
762→        }),
763→      },
764→    },
765→  };
766→}
767→
768→// ---------------------------------------------------------------------------
769→// rejectOrchestratorSession
770→// ---------------------------------------------------------------------------
771→
772→type RejectSessionInput = {
773→  surreal: Surreal;
774→  sessionId: string;
775→  feedback: string;
776→};
777→
778→export async function rejectOrchestratorSession(
779→  input: RejectSessionInput,
780→): Promise<RejectSessionResult> {
781→  const lookup = await lookupSession(input.surreal, input.sessionId);
782→  if (!lookup.ok) {
783→    return { ok: false, error: lookup.error };
784→  }
785→  const { session, record: sessionRecord, status } = lookup;
786→
787→  if (!REJECTABLE_STATUSES.has(status)) {
788→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "reject") };
789→  }
790→
791→  // 1. Update session status to active (agent resumes work)
792→  await input.surreal.update(sessionRecord).merge({
793→    orchestrator_status: "active" as OrchestratorStatus,
794→    last_feedback: input.feedback,
795→  });
796→
797→  // 2. Return task to in_progress
798→  if (session.task_id) {
799→    await input.surreal.update(session.task_id).merge({
800→      status: "in_progress",
801→      updated_at: new Date(),
802→    });
803→  }
804→
805→  return {
806→    ok: true,
807→    value: {
808→      rejected: true,
809→      continuing: true,
810→    },
811→  };
812→}
813→
814→// ---------------------------------------------------------------------------
815→// sendSessionPrompt
816→// ---------------------------------------------------------------------------
817→
818→type SendPromptInput = {
819→  surreal: Surreal;
820→  sessionId: string;
821→  text: string;
822→  adapter: SandboxAgentAdapter;
823→};
824→
825→export async function sendSessionPrompt(
826→  input: SendPromptInput,
827→): Promise<PromptSessionResult> {
828→  const lookup = await lookupSession(input.surreal, input.sessionId);
829→  if (!lookup.ok) {
830→    return { ok: false, error: lookup.error };
831→  }
832→  const { session, status } = lookup;
833→
834→  if (!PROMPTABLE_STATUSES.has(status)) {
835→    // Terminal sessions return 404 (session is "gone"), non-terminal return 409 (conflict)
836→    if (TERMINAL_STATUSES.has(status)) {
837→      return { ok: false, error: sessionNotFound(input.sessionId) };
838→    }
839→    return { ok: false, error: sessionStateConflict(input.sessionId, status, "prompt") };
840→  }
841→
842→  if (!session.external_session_id) {
843→    return {
844→      ok: false,
845→      error: {
846→        code: "SESSION_ERROR",
847→        message: `Session ${input.sessionId} has no external_session_id — cannot deliver prompt`,
848→        httpStatus: 500,
849→      },
850→    };
851→  }
852→
853→  try {
854→    const handle = await input.adapter.resumeSession(session.external_session_id);
855→    await handle.prompt([{ type: "text", text: input.text }]);
856→    return { ok: true, value: { delivered: true } };
857→  } catch (err) {
858→    return {
859→      ok: false,
860→      error: {
861→        code: "SESSION_ERROR",
862→        message: `Failed to deliver prompt: ${err instanceof Error ? err.message : String(err)}`,
863→        httpStatus: 500,
864→      },
865→    };
866→  }
867→}
868→

