  85→/** Result of evaluating governance policies for a tool call. */
  86→export type GovernanceVerdict =
  87→  | { readonly allowed: true }
  88→  | { readonly allowed: false; readonly reason: string; readonly outcome: "denied" | "rate_limited" };
