  90→/**
  91→ * Evaluate governance policies (pure function).
  92→ *
  93→ * Rules:
  94→ *   - "requires_human_approval" condition -> denied
  95→ *   - max_per_day exceeded -> denied
  96→ *   - Multiple policies: most restrictive wins (any denial = denied)
  97→ */
  98→export function evaluateGovernancePolicies(
  99→  policies: GovernsPolicyRow[],
 100→  todayExecutionCount: number,
 101→): GovernanceVerdict {
 102→  for (const policy of policies) {
 103→    // Check requires_human_approval condition
 104→    if (policy.conditions === "requires_human_approval") {
 105→      return {
 106→        allowed: false,
 107→        reason: `Tool call denied by policy "${policy.policyTitle}": requires human approval`,
 108→        outcome: "denied",
 109→      };
 110→    }
 111→
 112→    // Check max_per_day limit
 113→    if (policy.max_per_day !== undefined && todayExecutionCount >= policy.max_per_day) {
 114→      return {
 115→        allowed: false,
 116→        reason: `Tool call denied by policy "${policy.policyTitle}": daily limit of ${policy.max_per_day} exceeded (${todayExecutionCount} calls today)`,
 117→        outcome: "denied",
 118→      };
 119→    }
 120→  }
 121→
 122→  return { allowed: true };
 123→}
