 225→/**
 226→ * Execute all brain-native tool calls and return tool_result messages.
 227→ *
 228→ * - Each classified brain-native call is dispatched to its handler.
 229→ * - Unknown handlers produce an error result (graceful, not HTTP 500).
 230→ * - All errors are caught and returned as is_error tool_results.
 231→ */
 232→export async function executeBrainNativeTools(
 233→  classifiedCalls: ClassifiedToolCall[],
 234→  deps: ToolExecutorDeps,
 235→): Promise<ToolExecutionResult[]> {
 236→  const brainNativeCalls = classifiedCalls.filter(
 237→    (c): c is Extract<ClassifiedToolCall, { classification: "brain-native" }> =>
 238→      c.classification === "brain-native",
 239→  );
 240→
 241→  const results: ToolExecutionResult[] = [];
 242→
 243→  for (const call of brainNativeCalls) {
 244→    const handler = brainToolHandlers.get(call.toolUse.name);
 245→
 246→    if (!handler) {
 247→      results.push({
 248→        toolUseId: call.toolUse.id,
 249→        content: JSON.stringify({
 250→          error: `No handler registered for brain-native tool: ${call.toolUse.name}`,
 251→        }),
 252→        isError: true,
 253→      });
 254→      continue;
 255→    }
 256→
 257→    const startMs = performance.now();
 258→    try {
 259→      const result = await handler(call.toolUse.input, deps);
 260→      const durationMs = performance.now() - startMs;
 261→      results.push({
 262→        ...result,
 263→        toolUseId: call.toolUse.id,
 264→      });
 265→
 266→      // Fire-and-forget trace capture (do not block tool result delivery)
 267→      captureToolTrace(
 268→        {
 269→          toolName: call.toolUse.name,
 270→          workspaceId: deps.workspaceId,
 271→          identityId: deps.identityId,
 272→          sessionId: deps.sessionId,
 273→          outcome: "success",
 274→          durationMs,
 275→          input: call.toolUse.input as Record<string, unknown>,
 276→          output: { content: result.content },
 277→        },
 278→        { surreal: deps.surreal },
 279→      ).catch((traceError) => {
 280→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
 281→          tool_name: call.toolUse.name,
 282→          error: String(traceError),
 283→        });
 284→      });
 285→    } catch (error) {
 286→      const durationMs = performance.now() - startMs;
 287→      log.warn("proxy.tool_executor.handler_error", "Brain-native tool execution failed", {
 288→        tool_name: call.toolUse.name,
 289→        tool_use_id: call.toolUse.id,
 290→        error: String(error),
 291→      });
 292→      results.push({
 293→        toolUseId: call.toolUse.id,
 294→        content: JSON.stringify({
 295→          error: `Tool execution failed: ${String(error)}`,
 296→        }),
 297→        isError: true,
 298→      });
 299→
 300→      // Trace error outcome too
 301→      captureToolTrace(
 302→        {
 303→          toolName: call.toolUse.name,
 304→          workspaceId: deps.workspaceId,
 305→          identityId: deps.identityId,
 306→          sessionId: deps.sessionId,
 307→          outcome: "error",
 308→          durationMs,
 309→        },
 310→        { surreal: deps.surreal },
 311→      ).catch((traceError) => {
 312→        log.warn("proxy.tool_executor.trace_failed", "Tool trace capture failed", {
 313→          tool_name: call.toolUse.name,
 314→          error: String(traceError),
 315→        });
 316→      });
 317→    }
 318→  }
 319→
 320→  return results;
 321→}
