 345→  );
 346→  const mcpIntegrationCalls = classifiedCalls.filter(
 347→    (c) => c.classification === "integration" && !!c.resolvedTool.source_server_id,
 348→  );
 349→  const httpIntegrationCalls = classifiedCalls.filter(
 350→    (c) => c.classification === "integration" && !c.resolvedTool.source_server_id,
 351→  );
 352→
 353→  // Execute all partitions concurrently
 354→  const [brainResults, mcpResults, httpResults] = await Promise.all([
 355→    brainNativeCalls.length > 0
 356→      ? executeBrainNativeTools(brainNativeCalls, deps)
 357→      : Promise.resolve([]),
 358→    mcpIntegrationCalls.length > 0
 359→      ? executeIntegrationToolsViaMcp(mcpIntegrationCalls, deps, connectionMap)
 360→      : Promise.resolve([]),
 361→    httpIntegrationCalls.length > 0
 362→      ? executeIntegrationTools(httpIntegrationCalls, deps)
 363→      : Promise.resolve([]),
 364→  ]);
 365→
 366→  return [...brainResults, ...mcpResults, ...httpResults];
