 391→// ---------------------------------------------------------------------------
 392→// Response Sanitization (Pure Functions)
 393→// ---------------------------------------------------------------------------
 394→
 395→/** Headers that must be stripped from integration HTTP responses. */
 396→const SENSITIVE_HEADERS: ReadonlySet<string> = new Set([
 397→  "authorization",
 398→  "set-cookie",
 399→  "x-api-key",
 400→  "www-authenticate",
 401→]);
 402→
 403→/** JSON field names (lowercase) that must be recursively stripped from response bodies. */
 404→const SENSITIVE_FIELDS: ReadonlySet<string> = new Set([
 405→  "access_token",
 406→  "refresh_token",
 407→  "api_key",
 408→  "password",
 409→  "client_secret",
 410→  "bearer_token",
 411→]);
 412→
 413→/** Maximum response body size in bytes before truncation. */
 414→const MAX_RESPONSE_BYTES = 100 * 1024; // 100KB
 415→
 416→/**
 417→ * Strip sensitive headers from an HTTP response headers map.
 418→ * Pure function: returns a new record with sensitive headers removed.
 419→ */
 420→export function sanitizeResponseHeaders(
 421→  headers: Record<string, string>,
 422→): Record<string, string> {
 423→  const sanitized: Record<string, string> = {};
 424→  for (const [key, value] of Object.entries(headers)) {
 425→    if (!SENSITIVE_HEADERS.has(key.toLowerCase())) {
 426→      sanitized[key] = value;
 427→    }
 428→  }
 429→  return sanitized;
 430→}
 431→
 432→/**
 433→ * Recursively strip sensitive fields from a JSON value.
 434→ * Pure function: returns a new value with credential fields removed.
 435→ */
 436→export function sanitizeResponseBody(value: unknown): unknown {
 437→  if (value === null || value === undefined) return value;
 438→
 439→  if (Array.isArray(value)) {
 440→    return value.map(sanitizeResponseBody);
 441→  }
 442→
 443→  if (typeof value === "object") {
 444→    const sanitized: Record<string, unknown> = {};
 445→    for (const [key, fieldValue] of Object.entries(value as Record<string, unknown>)) {
 446→      if (!SENSITIVE_FIELDS.has(key.toLowerCase())) {
 447→        sanitized[key] = sanitizeResponseBody(fieldValue);
 448→      }
 449→    }
 450→    return sanitized;
 451→  }
 452→
 453→  return value;
 454→}
 455→
 456→/**
 457→ * Truncate a string to the maximum allowed byte size.
 458→ * Pure function: appends a truncation marker if the content exceeds the limit.
 459→ */
 460→export function truncateResponse(content: string): string {
 461→  const encoder = new TextEncoder();
 462→  const bytes = encoder.encode(content);
 463→  if (bytes.length <= MAX_RESPONSE_BYTES) return content;
 464→
 465→  const truncated = new TextDecoder().decode(bytes.slice(0, MAX_RESPONSE_BYTES));
 466→  return `${truncated}\n\n[Response truncated: ${bytes.length} bytes exceeds ${MAX_RESPONSE_BYTES} byte limit]`;
 467→}
 468→
 469→/**
 470→ * Full sanitization pipeline for integration tool responses.
 471→ * Pure function: sanitize body -> truncate -> return content string.
 472→ */
 473→export function sanitizeIntegrationResponse(
 474→  responseBody: string,
 475→  responseHeaders: Record<string, string>,
 476→): { content: string; sanitizedHeaders: Record<string, string> } {
 477→  const sanitizedHeaders = sanitizeResponseHeaders(responseHeaders);
 478→
 479→  // Try to parse and sanitize JSON body
 480→  let sanitizedContent: string;
 481→  try {
 482→    const parsed = JSON.parse(responseBody);
 483→    const sanitized = sanitizeResponseBody(parsed);
 484→    sanitizedContent = JSON.stringify(sanitized);
 485→  } catch {
 486→    // Not JSON -- use raw body
 487→    sanitizedContent = responseBody;
 488→  }
 489→
 490→  const truncatedContent = truncateResponse(sanitizedContent);
 491→
 492→  return { content: truncatedContent, sanitizedHeaders };
 493→}
