 601→                workspaceId: deps.workspaceId,
 602→                identityId: deps.identityId,
 603→                sessionId: deps.sessionId,
 604→                outcome: rateLimitVerdict.outcome,
 605→                durationMs,
 606→                input: { tool_kind: "integration", rate_limit_denial: rateLimitVerdict.reason },
 607→              },
 608→              { surreal: deps.surreal },
 609→            ).catch((traceError) => {
 610→              log.warn("proxy.rate_limit.trace_failed", "Rate limit trace capture failed", {
 611→                tool_name: call.toolUse.name,
 612→                error: String(traceError),
 613→              });
 614→            });
 615→            continue;
 616→          }
 617→        }
 618→      }
 619→
 620→      // Step 1: Resolve credentials
 621→      if (!deps.identityId) {
 622→        results.push({
 623→          toolUseId: call.toolUse.id,
 624→          content: JSON.stringify({ error: "Identity required for integration tool calls" }),
 625→          isError: true,
 626→        });
 627→        continue;
 628→      }
 629→
 630→      const credentialResolverDeps: CredentialResolverDeps = {
 631→        surreal: deps.surreal,
 632→        toolEncryptionKey: deps.toolEncryptionKey,
 633→      };
 634→
 635→      const credResult = await resolveCredentialsForTool(
 636→        call.toolUse.name,
 637→        deps.identityId,
 638→        credentialResolverDeps,
 639→      );
 640→
 641→      if (!credResult.ok) {
 642→        const durationMs = performance.now() - startMs;
 643→        results.push({
 644→          toolUseId: call.toolUse.id,
 645→          content: JSON.stringify({ error: `Credential resolution failed: ${credResult.error}` }),
 646→          isError: true,
 647→        });
 648→
 649→        captureToolTrace(
 650→          {
 651→            toolName: call.toolUse.name,
 652→            workspaceId: deps.workspaceId,
 653→            identityId: deps.identityId,
 654→            sessionId: deps.sessionId,
 655→            outcome: "error",
 656→            durationMs,
 657→            input: { tool_kind: "integration", credential_provider: providerRef },
 658→          },
 659→          { surreal: deps.surreal },
 660→        ).catch((traceError) => {
 661→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
 662→            tool_name: call.toolUse.name,
 663→            error: String(traceError),
 664→          });
 665→        });
 666→        continue;
 667→      }
 668→
 669→      // Step 2: Build and execute HTTP request
 670→      // The tool input should contain the endpoint URL or we derive it from provider config
 671→      const endpointUrl = typeof call.toolUse.input.endpoint_url === "string"
 672→        ? call.toolUse.input.endpoint_url
 673→        : typeof call.toolUse.input.url === "string"
 674→          ? call.toolUse.input.url
 675→          : undefined;
 676→
 677→      if (!endpointUrl) {
 678→        const durationMs = performance.now() - startMs;
 679→        results.push({
 680→          toolUseId: call.toolUse.id,
 681→          content: JSON.stringify({ error: "Integration tool call missing endpoint_url or url in input" }),
 682→          isError: true,
 683→        });
 684→
 685→        captureToolTrace(
 686→          {
 687→            toolName: call.toolUse.name,
 688→            workspaceId: deps.workspaceId,
 689→            identityId: deps.identityId,
 690→            sessionId: deps.sessionId,
 691→            outcome: "error",
 692→            durationMs,
 693→            input: { tool_kind: "integration", credential_provider: providerRef },
 694→          },
 695→          { surreal: deps.surreal },
 696→        ).catch((traceError) => {
 697→          log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
 698→            tool_name: call.toolUse.name,
 699→            error: String(traceError),
 700→          });
 701→        });
 702→        continue;
 703→      }
 704→
 705→      const httpMethod = typeof call.toolUse.input.method === "string"
 706→        ? call.toolUse.input.method.toUpperCase()
 707→        : "POST";
 708→
 709→      const requestHeaders: Record<string, string> = {
 710→        "Content-Type": "application/json",
 711→        ...credResult.headers,
 712→      };
 713→
 714→      // Build request body from tool input (excluding meta fields)
 715→      const { endpoint_url: _eu, url: _u, method: _m, ...bodyInput } = call.toolUse.input;
 716→      const hasBody = httpMethod !== "GET" && httpMethod !== "HEAD" && Object.keys(bodyInput).length > 0;
 717→
 718→      const fetchOptions: RequestInit = {
 719→        method: httpMethod,
 720→        headers: requestHeaders,
 721→        ...(hasBody ? { body: JSON.stringify(bodyInput) } : {}),
 722→      };
 723→
 724→      const httpResponse = await fetch(endpointUrl, fetchOptions);
 725→      const responseBody = await httpResponse.text();
 726→      const durationMs = performance.now() - startMs;
 727→
 728→      // Step 3-4: Sanitize and truncate
 729→      const responseHeaders: Record<string, string> = {};
 730→      httpResponse.headers.forEach((value, key) => {
 731→        responseHeaders[key] = value;
 732→      });
 733→
 734→      const { content } = sanitizeIntegrationResponse(responseBody, responseHeaders);
 735→
 736→      // Step 5: Return as tool_result
 737→      const isError = httpResponse.status >= 400;
 738→      const resultContent = isError
 739→        ? JSON.stringify({
 740→            error: `Integration API returned ${httpResponse.status}`,
 741→            status: httpResponse.status,
 742→            body: content,
 743→          })
 744→        : content;
 745→
 746→      results.push({
 747→        toolUseId: call.toolUse.id,
 748→        content: resultContent,
 749→        isError,
 750→      });
 751→
 752→      // Step 6: Write trace record
 753→      captureToolTrace(
 754→        {
 755→          toolName: call.toolUse.name,
 756→          workspaceId: deps.workspaceId,
 757→          identityId: deps.identityId,
 758→          sessionId: deps.sessionId,
 759→          outcome: isError ? "error" : "success",
 760→          durationMs,
 761→          input: { tool_kind: "integration", credential_provider: providerRef },
 762→          output: { status: httpResponse.status, content_length: content.length },
 763→        },
 764→        { surreal: deps.surreal },
 765→      ).catch((traceError) => {
 766→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
 767→          tool_name: call.toolUse.name,
 768→          error: String(traceError),
 769→        });
 770→      });
 771→    } catch (error) {
 772→      const durationMs = performance.now() - startMs;
 773→
 774→      // Integration errors are tool_result errors, not HTTP 500s
 775→      log.warn("proxy.integration_executor.error", "Integration tool execution failed", {
 776→        tool_name: call.toolUse.name,
 777→        tool_use_id: call.toolUse.id,
 778→        error: String(error),
 779→      });
 780→
 781→      results.push({
 782→        toolUseId: call.toolUse.id,
 783→        content: JSON.stringify({
 784→          error: `Integration tool execution failed: ${String(error)}`,
 785→        }),
 786→        isError: true,
 787→      });
 788→
 789→      captureToolTrace(
 790→        {
 791→          toolName: call.toolUse.name,
 792→          workspaceId: deps.workspaceId,
 793→          identityId: deps.identityId,
 794→          sessionId: deps.sessionId,
 795→          outcome: "error",
 796→          durationMs,
 797→          input: { tool_kind: "integration", credential_provider: providerRef },
 798→        },
 799→        { surreal: deps.surreal },
 800→      ).catch((traceError) => {
 801→        log.warn("proxy.integration_executor.trace_failed", "Integration trace capture failed", {
 802→          tool_name: call.toolUse.name,
 803→          error: String(traceError),
 804→        });
 805→      });
 806→    }
 807→  }
 808→
 809→  return results;
 810→}
