 812→// ---------------------------------------------------------------------------
 813→// Effect Boundary: executeIntegrationToolsViaMcp
 814→// ---------------------------------------------------------------------------
 815→
 816→/**
 817→ * Execute integration tool calls via MCP protocol for tools sourced from
 818→ * upstream MCP servers (those with source_server_id on ResolvedTool).
 819→ *
 820→ * For each tool call:
 821→ *   1. Load mcp_server record from source_server_id
 822→ *   2. Resolve credentials if server has a linked provider
 823→ *   3. Connect to upstream MCP server via mcpClientFactory
 824→ *   4. Call tools/call with the tool name and input
 825→ *   5. Extract content from CallToolResult
 826→ *   6. Return as tool_result
 827→ *   7. Write trace record
 828→ *
 829→ * Uses a shared connection map so multiple calls to the same server reuse
 830→ * one connection within a single proxy request.
 831→ */
 832→export async function executeIntegrationToolsViaMcp(
 833→  classifiedCalls: ClassifiedToolCall[],
 834→  deps: McpExecutorDeps,
 835→  connectionMap?: Map<string, Awaited<ReturnType<McpClientFactory["connect"]>>>,
 836→): Promise<ToolExecutionResult[]> {
 837→  const integrationCalls = classifiedCalls.filter(
 838→    (c): c is Extract<ClassifiedToolCall, { classification: "integration" }> =>
 839→      c.classification === "integration" && !!c.resolvedTool.source_server_id,
 840→  );
 841→
 842→  const results: ToolExecutionResult[] = [];
 843→  const localConnections = connectionMap ?? new Map<string, Awaited<ReturnType<McpClientFactory["connect"]>>>();
 844→
 845→  for (const call of integrationCalls) {
 846→    const startMs = performance.now();
 847→    const serverId = call.resolvedTool.source_server_id!;
 848→
 849→    try {
 850→      // Governance check
 851→      const governancePolicies = await fetchGovernancePolicies(
 852→        deps.surreal,
 853→        call.toolUse.name,
 854→      );
 855→
 856→      if (governancePolicies.length > 0) {
 857→        const todayCount = await countTodayToolExecutions(
 858→          deps.surreal,
 859→          call.toolUse.name,
 860→          deps.workspaceId,
 861→        );
 862→
 863→        const governanceVerdict = evaluateGovernancePolicies(governancePolicies, todayCount);
 864→        if (!governanceVerdict.allowed) {
 865→          results.push({
 866→            toolUseId: call.toolUse.id,
 867→            content: JSON.stringify({ error: governanceVerdict.reason }),
 868→            isError: true,
 869→          });
 870→          continue;
 871→        }
 872→      }
 873→
 874→      // Rate limit check
 875→      if (deps.identityId) {
 876→        const { maxCallsPerHour } = await fetchCanUseRateLimit(
 877→          deps.surreal,
 878→          deps.identityId,
 879→          call.toolUse.name,
 880→        );
 881→
 882→        if (maxCallsPerHour !== undefined) {
 883→          const hourlyCount = await countHourlyToolExecutions(
 884→            deps.surreal,
 885→            call.toolUse.name,
 886→            deps.workspaceId,
 887→            deps.identityId,
 888→          );
 889→
 890→          const rateLimitVerdict = evaluateRateLimit(maxCallsPerHour, hourlyCount);
 891→          if (!rateLimitVerdict.allowed) {
 892→            results.push({
 893→              toolUseId: call.toolUse.id,
 894→              content: JSON.stringify({ error: rateLimitVerdict.reason }),
 895→              isError: true,
 896→            });
 897→            continue;
 898→          }
 899→        }
 900→      }
 901→
 902→      // Load MCP server record
 903→      const serverRecord = new RecordId("mcp_server", serverId);
 904→      const workspaceRecord = new RecordId("workspace", deps.workspaceId);
 905→      const serverRow = await getMcpServerById(deps.surreal, serverRecord, workspaceRecord);
 906→
 907→      if (!serverRow) {
 908→        results.push({
 909→          toolUseId: call.toolUse.id,
 910→          content: JSON.stringify({ error: `MCP server ${serverId} not found` }),
 911→          isError: true,
 912→        });
 913→        continue;
 914→      }
 915→
 916→      // Resolve credentials if server has a linked provider
 917→      let authHeaders: Record<string, string> | undefined;
 918→      if (serverRow.provider && deps.identityId) {
 919→        const credResult = await resolveCredentialsForTool(
 920→          call.toolUse.name,
 921→          deps.identityId,
 922→          { surreal: deps.surreal, toolEncryptionKey: deps.toolEncryptionKey },
 923→        );
 924→
 925→        if (credResult.ok) {
 926→          authHeaders = credResult.headers;
 927→        }
 928→      }
 929→
 930→      // Connect (or reuse existing connection)
 931→      let connection = localConnections.get(serverId);
 932→      if (!connection) {
 933→        connection = await deps.mcpClientFactory.connect(
 934→          serverRow.url,
 935→          serverRow.transport as McpTransport,
 936→          authHeaders,
 937→        );
 938→        localConnections.set(serverId, connection);
 939→      }
 940→
 941→      // Call tool via MCP protocol
 942→      const callResult = await deps.mcpClientFactory.callTool(
 943→        connection.client,
 944→        call.toolUse.name,
 945→        call.toolUse.input as Record<string, unknown>,
 946→      );
 947→
 948→      const durationMs = performance.now() - startMs;
 949→
 950→      // Extract content from CallToolResult
 951→      const contentParts: string[] = [];
 952→      if (callResult.structuredContent) {
 953→        contentParts.push(JSON.stringify(callResult.structuredContent));
 954→      } else if (callResult.content && Array.isArray(callResult.content)) {
 955→        for (const block of callResult.content as Array<{ type: string; text?: string; resource?: { text?: string; uri?: string } }>) {
 956→          if (block.type === "text" && block.text) {
 957→            contentParts.push(block.text);
 958→          } else if (block.type === "resource" && block.resource) {
 959→            contentParts.push(block.resource.text ?? block.resource.uri ?? "");
 960→          }
 961→        }
 962→      }
 963→
 964→      const content = truncateResponse(contentParts.join("\n"));
 965→      const isError = callResult.isError === true;
 966→
 967→      results.push({
 968→        toolUseId: call.toolUse.id,
 969→        content: isError ? JSON.stringify({ error: content }) : content,
 970→        isError,
 971→      });
 972→
 973→      captureToolTrace(
 974→        {
 975→          toolName: call.toolUse.name,
 976→          workspaceId: deps.workspaceId,
 977→          identityId: deps.identityId,
 978→          sessionId: deps.sessionId,
 979→          outcome: isError ? "error" : "success",
 980→          durationMs,
 981→          input: { tool_kind: "mcp_integration", server_id: serverId },
 982→          output: { content_length: content.length },
 983→        },
 984→        { surreal: deps.surreal },
 985→      ).catch((traceError) => {
 986→        log.warn("proxy.mcp_executor.trace_failed", "MCP tool trace capture failed", {
 987→          tool_name: call.toolUse.name,
 988→          error: String(traceError),
 989→        });
 990→      });
 991→    } catch (error) {
 992→      const durationMs = performance.now() - startMs;
 993→
 994→      log.warn("proxy.mcp_executor.error", "MCP integration tool execution failed", {
 995→        tool_name: call.toolUse.name,
 996→        tool_use_id: call.toolUse.id,
 997→        server_id: serverId,
 998→        error: String(error),
 999→      });
1000→
1001→      results.push({
1002→        toolUseId: call.toolUse.id,
1003→        content: JSON.stringify({
1004→          error: `MCP tool execution failed: ${String(error)}`,
1005→        }),
1006→        isError: true,
1007→      });
1008→
1009→      captureToolTrace(
1010→        {
1011→          toolName: call.toolUse.name,
1012→          workspaceId: deps.workspaceId,
1013→          identityId: deps.identityId,
1014→          sessionId: deps.sessionId,
1015→          outcome: "error",
1016→          durationMs,
1017→          input: { tool_kind: "mcp_integration", server_id: serverId },
1018→        },
1019→        { surreal: deps.surreal },
1020→      ).catch((traceError) => {
1021→        log.warn("proxy.mcp_executor.trace_failed", "MCP tool trace capture failed", {
1022→          tool_name: call.toolUse.name,
1023→          error: String(traceError),
1024→        });
1025→      });
1026→    }
1027→  }
1028→
1029→  return results;
1030→}
