 92→/**
 93→ * Apply the base schema to a SurrealDB instance.
 94→ *
 95→ * DEFINE ANALYZER cannot run inside a transaction in SurrealDB v3.0+.
 96→ * The SDK may treat a multi-statement .query() as an implicit transaction,
 97→ * causing the analyzer and dependent FULLTEXT indexes to fail silently.
 98→ *
 99→ * We split the schema into three phases:
100→ * 1. DEFINE ANALYZER (must run outside any transaction)
101→ * 2. Schema definitions (DEFINE TABLE/FIELD/INDEX) — batch is fine
102→ * 3. Seed data (CREATE statements) — separate batch to isolate from index errors
103→ */
104→export async function applyTestSchema(surreal: Surreal): Promise<void> {
105→  const schemaSql = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
106→
107→  // Strip full-line comments before splitting — comments may contain semicolons
108→  // (e.g. "-- The edge is the source of truth; status is a derived consequence.")
109→  // which would create spurious fragments after the split.
110→  const withoutComments = schemaSql
111→    .split("\n")
112→    .filter((line) => !line.trimStart().startsWith("--"))
113→    .join("\n");
114→
115→  // Brace-aware split: only split on `;` outside `{...}` blocks.
116→  // DEFINE FUNCTION and DEFINE EVENT bodies contain semicolons that must not
117→  // be treated as statement terminators.
118→  const statements = splitSqlStatements(withoutComments);
119→
120→  // Phase 1: DEFINE ANALYZER (must be isolated)
121→  const analyzerStmts = statements.filter((s) => s.startsWith("DEFINE ANALYZER"));
122→  for (const stmt of analyzerStmts) {
123→    await surreal.query(stmt + ";");
124→  }
125→
126→  // Phase 2: Schema definitions (DEFINE TABLE/FIELD/INDEX/FUNCTION/EVENT)
127→  const schemaStmts = statements.filter(
128→    (s) => !s.startsWith("DEFINE ANALYZER") && !s.startsWith("CREATE"),
129→  );
130→  if (schemaStmts.length > 0) {
131→    await surreal.query(schemaStmts.map((s) => s + ";").join("\n"));
132→  }
133→
134→  // Phase 3: Seed data (CREATE statements) — isolated so index issues don't block seeds
135→  const seedStmts = statements.filter((s) => s.startsWith("CREATE"));
136→  if (seedStmts.length > 0) {
137→    await surreal.query(seedStmts.map((s) => s + ";").join("\n"));
138→  }
139→}
