/**
 * Acceptance Tests: Intent-Gated MCP Tool Access (Agent MCP Governance)
 *
 * Exercises the dynamic MCP endpoint that gates external tool calls behind
 * intent authorization and policy evaluation for sandbox coding agents.
 *
 * Traces: US-01 (tools/list), US-02 (tools/call), US-03 (create_intent),
 *         US-04 (human veto), US-05 (observer resume), US-06 (constraints),
 *         US-07 (composite intents), US-08 (dedup)
 *
 * Driving ports:
 *   POST /mcp/agent/:sessionName  (tools/list, tools/call, create_intent)
 *
 * Auth: X-Brain-Auth proxy token (no DPoP)
 */
import { describe, expect, it } from "bun:test";
import { createHash } from "node:crypto";
import { RecordId } from "surrealdb";
import {
  setupAcceptanceSuite,
  type AcceptanceTestRuntime,
} from "./acceptance-test-kit";
import {
  createWorkspaceDirectly,
  createIntentDirectly,
} from "./shared-fixtures";

// ── Types ──

type ToolsListResult = {
  jsonrpc: string;
  id: string | number;
  result?: { tools: Array<{ name: string; description: string; inputSchema?: Record<string, unknown> }> };
  error?: { code: number; message: string; data?: unknown };
};

type ToolsCallResult = {
  jsonrpc: string;
  id: string | number;
  result?: unknown;
  error?: { code: number; message: string; data?: Record<string, unknown> };
};

type CreateIntentResult = {
  jsonrpc: string;
  id: string | number;
  result?: { status: string; intentId?: string; reason?: string };
  error?: { code: number; message: string; data?: unknown };
};

// ── Mock MCP Client Factory ──

function createMockMcpClientFactory() {
  const calls: Array<{ toolName: string; args: Record<string, unknown> }> = [];
  let nextResult: unknown = { content: [{ type: "text", text: "mock-result" }] };

  return {
    calls,
    setNextResult(result: unknown) { nextResult = result; },
    factory: {
      connect: async () => ({
        listTools: async () => ({ tools: [] }),
        callTool: async (name: string, args: Record<string, unknown>) => {
          calls.push({ toolName: name, args });
          return nextResult;
        },
        close: async () => {},
      }),
    },
  };
}

// ── Suite Setup ──

const mockMcp = createMockMcpClientFactory();

const getRuntime = setupAcceptanceSuite("agent_mcp_governance", {
  configOverrides: {
    sandboxAgentEnabled: true,
    sandboxAgentType: "claude",
    orchestratorMockAgent: true,
  },
  mcpClientFactoryOverride: mockMcp.factory as never,
});

// ── Test Helpers ──

async function createTestSession(
  surreal: AcceptanceTestRuntime["surreal"],
  workspaceId: string,
  opts?: { status?: string },
): Promise<{ sessionId: string; sessionRecord: RecordId<"agent_session"> }> {
  const sessionId = `sess-${crypto.randomUUID()}`;
  const sessionRecord = new RecordId("agent_session", sessionId);

  await surreal.query(`CREATE $record CONTENT $content;`, {
    record: sessionRecord,
    content: {
      workspace: new RecordId("workspace", workspaceId),
      agent: "claude",
      session_type: "sandbox_agent",
      provider: "local",
      orchestrator_status: opts?.status ?? "active",
      external_session_id: `ext-${sessionId}`,
      created_at: new Date(),
      started_at: new Date(),
    },
  });

  return { sessionId, sessionRecord };
}

async function seedProxyTokenWithSession(
  surreal: AcceptanceTestRuntime["surreal"],
  identityId: string,
  workspaceId: string,
  sessionId: string,
): Promise<string> {
  const rawToken = `brn_test_${crypto.randomUUID()}`;
  const tokenHash = createHash("sha256").update(rawToken).digest("hex");
  const tokenId = `pt-${crypto.randomUUID()}`;

  await surreal.query(`CREATE $rec CONTENT $content;`, {
    rec: new RecordId("proxy_token", tokenId),
    content: {
      token_hash: tokenHash,
      workspace: new RecordId("workspace", workspaceId),
      identity: new RecordId("identity", identityId),
      session: new RecordId("agent_session", sessionId),
      expires_at: new Date(Date.now() + 24 * 60 * 60 * 1000),
      revoked: false,
      created_at: new Date(),
    },
  });

  return rawToken;
}

async function registerMcpTool(
  surreal: AcceptanceTestRuntime["surreal"],
  workspaceId: string,
  opts: { name: string; toolkit: string; riskLevel?: string; description?: string },
): Promise<{ toolId: string; toolRecord: RecordId<"mcp_tool"> }> {
  const toolId = `tool-${crypto.randomUUID()}`;
  const toolRecord = new RecordId("mcp_tool", toolId);

  await surreal.query(`CREATE $rec CONTENT $content;`, {
    rec: toolRecord,
    content: {
      name: opts.name,
      toolkit: opts.toolkit,
      description: opts.description ?? `${opts.toolkit}:${opts.name} tool`,
      input_schema: { type: "object", properties: {} },
      risk_level: opts.riskLevel ?? "low",
      workspace: new RecordId("workspace", workspaceId),
      status: "active",
      created_at: new Date(),
    },
  });

  return { toolId, toolRecord };
}

async function grantToolToIdentity(
  surreal: AcceptanceTestRuntime["surreal"],
  identityId: string,
  toolId: string,
): Promise<void> {
  await surreal.query(
    `RELATE $identity->can_use->$tool SET granted_at = time::now();`,
    {
      identity: new RecordId("identity", identityId),
      tool: new RecordId("mcp_tool", toolId),
    },
  );
}

async function createGatesEdge(
  surreal: AcceptanceTestRuntime["surreal"],
  intentId: string,
  sessionId: string,
): Promise<void> {
  await surreal.query(
    `RELATE $intent->gates->$sess SET created_at = time::now();`,
    {
      intent: new RecordId("intent", intentId),
      sess: new RecordId("agent_session", sessionId),
    },
  );
}

function mcpRequest(
  baseUrl: string,
  sessionId: string,
  proxyToken: string,
  method: string,
  params?: Record<string, unknown>,
): Promise<Response> {
  return fetch(`${baseUrl}/mcp/agent/${sessionId}`, {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "X-Brain-Auth": proxyToken,
    },
    body: JSON.stringify({
      jsonrpc: "2.0",
      id: crypto.randomUUID(),
      method,
      params: params ?? {},
    }),
  });
}

